window.__LIBQ=window.__LIBQ||{};window.__LIBQ["tien-nghich"]=window.__LIBQ["tien-nghich"]||{};window.__LIBQ["tien-nghich"]["q16"]=window.__LIBQ["tien-nghich"]["q16"]||{};window.__LIBQ["tien-nghich"]["q16"]["cotTruyen"]=[{"chuong":1633,"tieuDe":"Huyền La Nhập Phủ","tomTat":"Vương Lâm cầm Khai Thiên Phủ đại chiến tứ đại chiến tướng, dùng Đạo cổ bất diệt thể hứng chịu hợp kích bốn người mà không hề bị thương, nhận định tu vi bọn họ chỉ khoảng Không Huyền hậu kỳ chưa hoàn toàn khôi phục. Hắn dùng Tê Thiên lực qua cánh tay Diệp Mịch tàn sát hàng chục tiên nhân, xé khe không gian di chuyển giết liên tiếp. Sau đó ra lệnh U Minh thú mở miệng triệu hồi sương mù thiên đạo nuốt sạch khoảng bảy tám mươi tiên nhân, chỉ còn lại năm người — tứ đại chiến tướng và Chiến lão quỷ kinh hãi tột độ khi nhận ra đây chính là thiên đạo từng cắn nuốt Liên Đạo Phi. Hồn phách Thất Thải Tiên Tôn trong thân Chiến lão quỷ giành quyền điều khiển, hỏi Vương Lâm về hồn thứ ba nhưng Vương Lâm đáp chưa tìm được, rồi cưỡi U Minh thú rời đi hướng Côn Hư. Trong Côn Hư, Đạo nhân bảy màu đã tập hợp toàn bộ Cửu huyền huyết mạch, định dùng huyễn hóa luân hồi tìm hồn thứ ba. Ở Tiên Cương đại lục, một thanh niên bí ẩn tự xưng thuộc Đạo cổ nhất tộc xuất hiện tại dãy núi nơi có Thất Đạo Tông, tuyên bố đến đón một hài tử về nhà rồi mỉm cười tiến vào dãy núi."},{"chuong":1634,"tieuDe":"Ngũ Hành Tinh","tomTat":"Chương mở đầu bằng khái quát lịch sử Côn Hư tinh vực với hai cuộc đại chiến tàn khốc: lần một quyết chiến cùng La Thiên, lần hai giữa giới nội và giới ngoại khiến vô số tu chân tinh tan thành tro bụi. Giữa tinh hải tồn tại Ngũ Hành tinh — tu chân tinh thần bí linh khí vượt Thiên Vận Tinh, bên ngoài có năm quầng sáng ngũ sắc, thần thức không thể cảm nhận, ngay cả Tu Chân Liên Minh cũng không biết phương hướng. Trên đó chỉ có một tông phái duy nhất: Quy Nhất Tông, toàn bộ nằm trong ngọn tháp hơn 99 tầng. Vương Lâm cưỡi U Minh thú, dùng ngọc giản Nạp Đa đưa hơn ngàn năm trước để tìm tọa độ và đến được Ngũ Hành tinh. Qua dung hợp thiên đạo với U Minh thú, hắn nhận ra Ngũ Hành tinh vốn không thuộc động phủ giới mà được tu sĩ bên ngoài mang từ Tiên Cương đại lục tới. Hắn truyền âm vào tinh cầu xưng ước hẹn năm xưa với Nạp Đa, nhưng phó tông chủ Duẫn Đông Thân từ chối cho vào, nói Nạp Đa đã bế quan ngàn năm. Một luồng thần thức bá đạo từ bên trong thách thức: qua được Ngũ Hành trận thì cứ vào. Vương Lâm bất chấp bước thẳng vào quầng sáng ngũ sắc, chịu công kích liên tiếp từ lực lượng Ngũ Hành. Ở tầng cao tháp Quy Nhất Tông, bốn cường giả bàn luận — lão già mặc hắc bào tự tin Vương Lâm không thể qua ngũ quan, còn một nữ tử trung niên khắc bạc lại hi vọng hắn qua được để thấy cửu chuyển."},{"chuong":1635,"tieuDe":"Đại Địa Bổn Nguyên","tomTat":"Bốn trưởng lão Quy Nhất tông bàn bạc về Vương Lâm, lão già hắc bào tạo mặt gương quan sát và quyết định thử sức, nữ tử trung niên lộ tư thù với Tư Đồ Nam muốn Vương Lâm chịu trừng phạt thay. Trên tầng chín tháp, Nạp Đa cùng nam tử áo tím theo dõi, nhận định Vương Lâm chỉ Không Linh trung kỳ, có thể qua Ngũ Hành nhưng không thể vượt đệ tam chuyển của cửu chuyển trận pháp do chín lão tổ đồng thời bày ra. Vương Lâm bước mười bốn bước rưỡi xâm nhập quầng sáng Ngũ Hành, đối mặt trận thứ nhất — Đại địa thổ trận. Dùng thân thể Đạo cổ tung chín quyền đánh nát chín mặt người đất, bị đệ nhị biến hai mặt đất ép chặt nhưng thong thả phá vỡ từ bên trong, đồng thời thu luôn trận linh khiến tất cả chấn động. Trong tinh không Côn Hư, thanh niên tóc đen bí ẩn xuất hiện từ đám huyết sắc, không ai phát hiện, gọi Vương Lâm là đứa nhỏ và quyết định đi theo xem xét."},{"chuong":1636,"tieuDe":"Quân Hỏa Như Gia","tomTat":"Vương Lâm thu phục nhúm đất cát đã mơ hồ trở thành thổ bổn nguyên từ Ngũ Hành thổ trận, cất vào không gian trữ vật bên cạnh nhúm lấy từ Thiên Vận Tử trước đó. Hắn suy tính rằng nếu thu đủ bốn bổn nguyên còn lại ngoài hỏa bổn nguyên đã có thì tu vi sẽ tăng mạnh, đồng thời tự hỏi Ngũ Hành quy nhất có thể sản sinh bổn nguyên mới hay không. Bước vào Ngũ Hành hỏa trận, biển lửa tràn ngập nhưng Vương Lâm ngược lại càng thoải mái nhờ sở hữu hỏa bổn nguyên. Chín con hỏa Kỳ Lân phủ phục trước hắn như mèo con gặp chủ, toàn bộ lửa ngưng tụ thành người khổng lồ hỏa diễm cao mấy ngàn trượng mặc giáp lửa quỳ gối bái lạy sùng kính. Toàn bộ tu sĩ Quy Nhất tông chứng kiến qua dòng xoáy trên bầu trời đều kinh hãi sững sờ. Nạp Đa nhận ra Vương Lâm có hỏa bổn nguyên đạt cực điểm, kết luận Ngũ Hành tinh không vây nổi hắn. Thủy Tướng quyết định thỉnh tiên tổ chiến giáp — bộ áo giáp xanh nước biển tỏa sóng nước, triệu trường thương sóng nước, tuyên bố sẽ vào Ngũ Hành thủy trận bức Vương Lâm ra rồi tiến vào cửu chuyển, sau đó hóa thành hơi nước biến mất."},{"chuong":1637,"tieuDe":"Hóa Ra Hắn Tên Là Vương Lâm","tomTat":"Trong Ngũ Hành hỏa trận, Vương Lâm đứng trên đỉnh đầu người khổng lồ lửa chỉ huy nó cùng chín con Kỳ Lân phá sập hỏa trận, cảnh tượng chuyển sang Ngũ Hành thủy trận — hải dương vô tận với sóng gió mây đen. Ngũ tiên Thủy Tướng của Quy Nhất tông nổi lên từ biển, có thân thể thủy linh hoàn chỉnh là linh hồn thủy trận, dùng bốn bức tường nước vạn trượng và trường thương nước mưa huyễn hóa nhấn chìm Vương Lâm trong biển. Một lão già Tịnh Niết trung kỳ kích động đám đông bằng lời xuyên tạc, vu cho Vương Lâm giết toàn tộc họ Đằng vì tham bảo vật và vô ơn với Nạp Đa trưởng lão. Vương Lâm bất ngờ xuất hiện sau lưng Thủy Tướng, vỗ chưởng truyền lực lượng bổn nguyên và khí tức hủy diệt Đạo cổ khiến ngũ tạng Thủy Tướng tan nát, phun máu bị đánh bay, nhưng áo giáp trên người hắn phóng sinh cơ khôi phục thương thế. Vương Lâm dùng cấm chế bổn nguyên tự hình thành quy tắc nhìn thấu bí mật áo giáp: tu vi Thủy Tướng không tới bước thứ ba, áo giáp cho sức mạnh bước ba nhưng điều khiển ngược người mặc. Bên ngoài Ngũ Hành tinh, Huyền La Đại Thiên Tôn quan sát trận chiến, lần đầu biết tên Vương Lâm, cười vui vẻ nhận xét hắn nhìn ra bí mật áo giáp danh tiếng ở tiên tộc là rất giỏi."},{"chuong":1638,"tieuDe":"Càn Khôn Nhất Tích","tomTat":"Thủy Tướng bị Vương Lâm yêu cầu cởi áo giáp đổi mạng, từ chối và ném trường thương vào biển, phun máu bắt quyết thi triển thần thông Càn Khôn Nhất Tích do tổ tiên truyền — dùng thân thể thủy linh ngưng tụ toàn bộ nước biển và nước mưa thành quả cầu khổng lồ nhốt Vương Lâm, co rút ép thành một giọt chứa thủy bổn nguyên. Tuôn hết lực lượng áo giáp, thân thể héo rũ nổi mụn mủ, lộ bản chất chỉ là tu sĩ thiên nhân tứ suy đã trải bốn lần suy kiếp. Vương Lâm bị nhốt nhưng hoàn toàn có thể thoát dễ dàng, quyết định ở lại cảm ngộ thủy bổn nguyên — cơ hội cực hiếm nâng bổn nguyên từ bảy đạo lên tám đạo, dùng tơ máu trong đồng tử quan sát mọi biến hóa. Thủy Tướng cầu viện Nạp Đa, được lực lượng kim hệ bổ sung qua dòng xoáy trên bầu trời thủy trận (kim sinh thủy), vô tình giúp Vương Lâm cảm ngộ rõ hơn. Huyền La Đại Thiên Tôn quan sát từ ngoài tinh không Ngũ Hành tinh, nhận ra Thủy Tướng đang trợ giúp chứ không phải luyện hóa Vương Lâm, nhận xét Vương Lâm có huyết mạch Đạo cổ và tiên nhân thuật, cấm chế bổn nguyên trong tơ máu đồng tử hóa thành quy tắc chưa từng thấy trên ai, kết luận là Đạo tiên song tu."},{"chuong":1639,"tieuDe":"Đại Ân Như Vậy","tomTat":"Thủy Tướng dùng thần thông Càn Khôn Nhất Tích đè ép Vương Lâm trong thủy cầu chứa thủy bổn nguyên nồng đậm, Nạp Đa và toàn bộ Quy Nhất tông tự tin Vương Lâm không thể thoát. Tuy nhiên Vương Lâm lợi dụng chính sự đè ép để quan sát và minh ngộ toàn bộ biến hóa thủy bổn nguyên — ba triệu tám ngàn vạn lần biến hóa. Thủy Tướng phun máu gia tốc co rút thủy cầu nhưng vô tình cung cấp thêm biến hóa cho Vương Lâm. Nạp Đa mặc áo giáp kim quang dẫn mấy trăm tu sĩ phóng thần thức nhập trận hợp lực đè ép. Vương Lâm lấy giọt nước thủy bổn nguyên Thiên Vận Tử từng cho ra làm chìa khóa, hoàn tất minh ngộ, thu toàn bộ thủy cầu thành giọt nước thủy tinh trên tay rồi tiêu tán. Vương Lâm ôm quyền vái Thủy Tướng nói đại ân như vậy xin nhận một vái, rồi phất tay áo tống toàn bộ thần thức Quy Nhất tông ra khỏi trận pháp, chỉ giữ lại Thủy Tướng. Toàn bộ tu sĩ Quy Nhất tông bừng tỉnh trong sợ hãi tột độ, Nạp Đa mê man nhận ra Vương Lâm đã nắm được ba bổn nguyên."},{"chuong":1640,"tieuDe":"Bộ Đạp Tí Đoạn","tomTat":"Sau khi hấp thu Càn Khôn Nhất Tích, Vương Lâm có được mầm mống thủy bổn nguyên — bổn nguyên thứ tám, thuộc thực bổn nguyên cần dung hợp nhiều lần mới đại thành. Hắn hồi tưởng lại nguồn gốc lôi bổn nguyên (nuốt nửa con Lôi Long + lôi đình bất diệt Thiểm Lôi tộc) và hỏa bổn nguyên (Chu Tước tỉnh giấc), nhận định thổ bổn nguyên còn rất xa. Vương Lâm bắt lại Thủy Tướng đang bỏ chạy, truyền sinh cơ vào mi tâm tạo tấm màng ngăn hồn phách khỏi áo giáp đang hút sạch sinh cơ, rồi dùng huyết kiếm chém đứt tia máu liên kết tách hoàn chỉnh áo giáp ra, tuyên bố không giết vì Thủy Tướng có ân tặng mầm mống thủy bổn nguyên. Thủy Tướng cực kỳ suy yếu, biến mất trong Ngũ Hành thủy trận. Khi Vương Lâm đang nghiên cứu áo giáp, Ngũ Hành thủy trận sụp đổ, dòng xoáy xuất hiện với uy áp kinh khủng, một cánh tay khô héo vươn ra đoạt áo giáp. Vương Lâm bùng nổ toàn lực — bảy bổn nguyên dung hợp thành tu vi Không Linh hậu kỳ cộng Đạo cổ huyết mạch — đạp nát cánh tay kẻ kia, thu áo giáp và trường thương, bị nhận ra là tu sĩ cổ quốc. Huyền La Đại Thiên Tôn ở ngoài tinh không chứng kiến, khen Vương Lâm có gan hợp tính tình, nhắc tới Quy Nhất tông và nói phất tay có thể diệt sạch sinh linh trên tu chân tinh."},{"chuong":1641,"tieuDe":"Cửu Chuyển Tâm Luân","tomTat":"Vương Lâm thu hồi áo giáp, đối chưởng Đệ Cửu lão tổ Quy Nhất tông qua dòng xoáy — chỉ lùi ba bước trong khi lão tổ bị bẻ gãy cánh tay phải phun máu, nhờ áo giáp nội liễm mới không tan xác. Lão tổ nhận định Vương Lâm là người cổ tộc thuộc Đạo cổ nhất mạch, nghi đến từ Tiên Cương đại lục chứ không phải hậu nhân ba nghìn huyết mạch Diệp Mịch. Lão triệu Nạp Đa lên tầng chín hỏi lai lịch Vương Lâm. Vương Lâm chủ động bước vào Ngũ Hành mộc trận, dùng thuật Tê Thiên xé thiên địa làm đôi phá tan lá cây bao vây, ép mộc linh quy phục thu được tinh thể xanh biếc. Tiếp đó phá nốt Ngũ Hành kim trận — trận cuối cùng với vạn kiếm kim quang — khiến toàn bộ Ngũ Hành đại trận tan rã hoàn toàn. Đệ Cửu lão tổ giải thích về Cửu Chuyển Tâm Luân, trận pháp hộ sơn Quy Nhất tông dựa vào tâm bất động, mỗi chín nhịp thở một chuyển. Vương Lâm đang định bước vào Ngũ Hành tinh thì sững lại phát hiện tinh cầu bắt đầu chuyển động — Cửu Chuyển Tâm Luân đã kích hoạt."},{"chuong":1642,"tieuDe":"Duy Tâm Cố Động","tomTat":"Lão già kim bào ngồi tầng tháp thứ chín của Ngũ Hành tinh giải thích cơ chế trận pháp Cửu Chuyển Tâm Luân cho Nạp Đa — trọng điểm ở tâm, tâm động càng nhanh trận càng khó phá, người thông minh lại càng không thoát được. Huyền La Đại Thiên Tôn lơ lửng trong tinh không bên ngoài quan sát, nhận định đây là danh trận Tiên Cương đại lục, ngay cả Đạo cổ hoàng tôn đời này nếu chưa gặp cũng sẽ bị nhốt. Vương Lâm rơi vào trận, Ngũ Hành tinh xoay tròn cứ chín nhịp thở tăng tốc một chuyển, từ đệ nhất tới đệ ngũ chuyển hắn đã phun máu, tâm thần hao tổn cực độ, toàn thân nổi gân xanh, xúc động điên cuồng không thể đè nén. Từ đệ ngũ tới đệ cửu chuyển, hắn cố phân tích nhưng càng suy tư càng không thể tĩnh tâm. Lão già kim bào cười phá tuyên bố Vương Lâm chết chắc, rủ Nạp Đa đi nhặt xác. Huyền La Đại Thiên Tôn thất vọng, giơ tay định ra tay cứu. Nhưng chuyển động đột ngột chậm lại — Vương Lâm ngộ ra bản chất trận pháp: mọi thứ chuyển động đều do tâm mình không tĩnh, tâm động cho nên thần động, thân động. Hắn nhắm mắt, tơ máu tiêu tán, điên cuồng tiêu tán, xúc động tiêu tán, chỉ còn sự bình tĩnh như nước giếng cổ không chút gợn sóng, bước đầu phá giải trận pháp."},{"chuong":1643,"tieuDe":"Thân Tình Dẫn Tâm","tomTat":"Trong đệ cửu chuyển của Cửu Chuyển Tâm Luân, Vương Lâm nhận ra Chân Giả bổn nguyên vô dụng vì tất cả đều từ tâm, nên sáng tạo phương pháp thân tình dẫn tâm: thân tĩnh dẫn hồn tĩnh dẫn thần tĩnh dẫn tâm tĩnh, chín nhịp thở phá hoàn toàn trận pháp. Huyền La Đại Thiên Tôn quan sát từ bên ngoài, phân tích chính xác nguyên lý và tuyên bố nhất định phải thu phục Vương Lâm. Vương Lâm không rời trận mà nghịch chuyển trận pháp bằng nguyên lý tâm động thì tinh động, đảo ngược Cửu Chuyển Tâm Luân đánh vào tu sĩ Quy Nhất tông trên Ngũ Hành tinh. Tu sĩ thường hôn mê ở đệ tứ chuyển, Nạp Đa cũng hôn mê ở đệ tứ chuyển, lão già kim bào chống tới đệ thất chuyển mới phun máu suy kiệt. Ba lão già ẩn ở tầng năm, sáu, bảy của ngọn tháp đồng loạt lao ra phá vỡ trận pháp đang nghịch chuyển, giải cứu tu sĩ Quy Nhất tông. Vương Lâm một thân bạch y hiện thân trên bầu trời Ngũ Hành tinh."},{"chuong":1644,"tieuDe":"Tai Vách Mạch Rừng","tomTat":"Ngũ Hành tinh hư ảo sụp đổ sau nghịch động Cửu Chuyển Tâm Luân, Vương Lâm xuất hiện trên bầu trời quan sát mấy trăm tu sĩ hôn mê cùng Nạp Đa và lão già kim bào bị thương. Ba nam tử trung niên từ Tiên Cương đại lục nhận ra hắn thuộc Đạo Cổ nhất mạch, đồng loạt ra tay nhưng bị lực trùng kích từ hư ảnh Đạo Cổ sụp đổ đẩy lui. Thanh niên hắc y Vân Dật Phong — đệ tử trung tâm thứ ba Quy Nhất tông, từng gặp trong thiên kiếp — bước ra từ tầng bốn thi triển Lục Hoa Ấn giao chiến ngang sức, để lại sáu đóa hoa đen gây rữa nát cánh tay Vương Lâm. Nhờ Đạo Cổ bất diệt thể khôi phục nhanh hơn đối thủ vài nhịp thở, Vương Lâm lợi dụng khoảng hở đánh quyền phá sập tháp từ tầng một tới tầng bốn, chỉ còn ba tầng gốc từ Tiên Cương lơ lửng tỏa sáng. Mục đích của hắn là bức hết lực lượng ẩn giấu lộ diện, xác định sức mạnh chiếc đinh thứ hai sau Thiên Vận Tử để lên kế hoạch tìm hồn thứ ba. Từ ba tầng tháp còn lại vang lên giọng nói già nua uy nghiêm sỉ nhục Đạo Cổ nhất mạch là nhánh yếu nhất, khiến Huyền La Đại Thiên Tôn bên ngoài Ngũ Hành tinh thần sắc âm trầm — cả đời chưa bao giờ gặp ai dám vũ nhục Đạo Cổ nhất mạch."},{"chuong":1645,"tieuDe":"Song Hành Khải","tomTat":"Vân Dật Phong nghe lời lão già trong tháp rồi thở dài bỏ đi, không can thiệp chuyện Vương Lâm. Từ tầng thứ ba tháp cao, lão già tóc bạc tu vi Không Huyền trung kỳ bước ba bước ra, lập phòng hộ quanh tháp và tuyên bố bắt Vương Lâm, phán đoán sai hắn là người Đạo cổ nhất mạch từ Tiên Cương đại lục tới tìm Diệp Mịch. Lão già dùng roi xanh biếc mộc lực Ngũ Hành tấn công, roi hấp thu sinh cơ cây cỏ bổ sung bổn nguyên, quất trúng Vương Lâm khiến hắn lui mấy bước. Vương Lâm rút Côn Cực tiên đấu roi, nhờ huyết mạch Đạo cổ, bảy đạo bổn nguyên và cánh tay Diệp Mịch, khí lực áp đảo giật đứt roi lão già. Lão già thu hồi tàn dư roi hợp nhất với cơn lốc đất cát thành áo giáp Quy Nhất tông mộc + thổ, tu vi tăng vọt lên Không Huyền hậu kỳ đỉnh phong nhưng chịu phản phệ đau đớn. Lão già hút hết cây cỏ Ngũ Hành tinh tạo mộc nhân khổng lồ mấy ngàn trượng kết hợp lốc đất tấn công Vương Lâm. Vương Lâm bình tĩnh kích hoạt Đạo cổ bất diệt thể bao phủ toàn thân chủ động chịu đòn. Huyền La Đại Thiên Tôn quan sát từ bên ngoài, nhận xét đây cùng loại với tiên nhân bất diệt thể và thắc mắc Vương Lâm muốn làm gì."},{"chuong":1646,"tieuDe":"Huyền La Đại Thiên Tôn","tomTat":"Vương Lâm rút lui an toàn khỏi Ngũ Hành tinh trên lưng U Minh thú đã huyễn hóa vô hình, áp chế thương thế rồi rời đi về Côn Hư. Hắn phân tích tu vi lão già họ Mã có thể mạnh hơn Chưởng Tôn, đã trải qua mấy lần huyền kiếp, và nhận ra bộ áo giáp tầng nhất tháp cao rất có thể thuộc về lão. Hắn còn hậu thủ là cây cung của Lý Quảng chưa dùng. Trên Ngũ Hành tinh, Vân Dật Phong phân tích cho lão già họ Mã: thiên đạo của Vương Lâm đã bị phân chia, không hoàn chỉnh, không thể nuốt người tu vi cao thâm, và suy đoán Vương Lâm đến đây để bức lộ toàn bộ lực lượng ẩn giấu trước khi tìm hồn thứ ba. Đúng lúc lão già họ Mã muốn quay về tháp, Huyền La Đại Thiên Tôn giáng lâm với uy áp kinh thiên — đại địa rung chuyển, mặt trời tắt sáng, ba nam tử trung niên phun máu bật bay. Đại Thiên Tôn chất vấn ai dám nói Đạo cổ nhất mạch là đám hoang dã, bóp cổ lão già mặc song hành khải và phá nát bộ song hành giáp như tờ giấy. Lão già họ Mã run rẩy nhận ra danh tính Huyền La Đại Thiên Tôn, phun máu hoảng sợ."},{"chuong":1647,"tieuDe":"Một Ngày Đặc Biệt","tomTat":"Huyền La Đại Thiên Tôn hiện thân ảnh mơ hồ trên Ngũ Hành tinh, uy áp cửu dương khiến mọi người không thể nhìn rõ diện mạo, vuốt tay giết lão già mất áo giáp rồi phóng uy áp buộc tất cả quỳ gối. Vân Dật Phong kiên trì chống cự cho đến khi phun máu mới sụp xuống, được Huyền La khen tâm trí cực cao nhưng tiếc không thuộc Đạo cổ nhất mạch. Huyền La phá tầng tháp thứ nhất đoạt tấm áo giáp đen kịt, ra lệnh bọn Quy Nhất tông ở lại chưa được đi. Vân Dật Phong thề trở thành Đại Thiên Tôn mặt trời thứ mười một, cùng lão già họ Mã phân tích rằng Huyền La đang khảo nghiệm Vương Lâm và muốn họ làm hòn đá mài đao rèn luyện hắn. Vương Lâm cưỡi U Minh thú chữa thương, xác nhận đã bức Quy Nhất tông ra khỏi cuộc tranh đoạt hồn thứ ba, quyết tâm tự mình tìm kiếm. Trước khi vào tiên giới, Vương Lâm đột ngột quay người vung gió lốc bảy đạo bổn nguyên thăm dò kẻ theo dõi — thực chất đề phòng lão già họ Mã, không biết Huyền La ẩn thân phía sau. Huyền La tổng kết đánh giá Vương Lâm qua bốn lần quan sát: bá đạo, minh ngộ, quyết đoán, cẩn thận, nhưng đặt tiêu chí cuối cùng cần kiểm chứng là trọng nghĩa tình. Vương Lâm trở về tiên giới đứng trước ngọn núi bế quan cũ, thần sắc ảm đạm — hôm nay là một ngày đặc biệt mà mỗi năm hắn đều cố bận rộn để quên đi nỗi nhung nhớ."},{"chuong":1648,"tieuDe":"Hạnh Phúc Trong Mộng Ảo","tomTat":"Trong ngày kỷ niệm gặp Lý Mộ Uyển mỗi năm, Vương Lâm dùng tấm buồm mặt quỷ che thân ngồi một mình trên ngọn núi trong động phủ giới, uống rượu giải sầu nhưng không xoa dịu nổi. Hắn mở Tỵ Thiên Quan vuốt ve khuôn mặt Lý Mộ Uyển đang hôn mê, rơi lệ, xác nhận một phần hồn phách của nàng đã bị mất và thề sẽ thu hồi bằng mọi giá. Hắn nhắc việc đã tiếp nhận Lý Thiến Mai, xin lỗi Uyển Nhi, thề cả đời không dính tới tình cảm nào nữa. Sau đó hắn thi triển thần thông Mặt quỷ nhập huyễn, mộng ảo ngàn năm — kết hợp tấm buồm mặt quỷ và tiếp xúc mi tâm Lý Mộ Uyển để nhập mộng ảo, tái hiện lần gặp gỡ đầu tiên hơn hai ngàn năm trước ở hải ngoại. Trong mộng, hắn cứu nàng khỏi trưởng lão dâm tà Tuyên Vũ Viên đang đuổi giết, chỉ liếc mắt phá tan phi kiếm giết kẻ địch, ôm nàng rồi mỉm cười nhìn nàng sợ hãi rời đi. Huyền La Đại Thiên Tôn đứng trong ngọn núi quan sát, phóng thần thức vào sương mù chứng kiến toàn bộ mộng ảo, cảm thán về nỗi bi ai khiến Vương Lâm phải vào mộng tìm hạnh phúc. Khi mộng ảo tan, Vương Lâm mở mắt trở về tiên giới, nhìn mặt trăng tròn cô đơn trên trời, bên trong như có thân ảnh một nam một nữ đi cùng nhau."},{"chuong":1649,"tieuDe":"Tìm Kiếm Hồn Thứ Ba","tomTat":"Vương Lâm ngồi suốt đêm dưới ánh trăng bên Lý Mộ Uyển đang say ngủ trong Tỵ Thiên Quan, trong khi Lý Thiến Mai cùng phụ thân lặng lẽ quan sát từ xa rồi quay bước rời đi trong cô độc. Sáng sớm, Vương Lâm thu Tỵ Thiên Quan và xác định hướng tìm hồn thứ ba từ đạo nhân bảy màu và Chiến lão quỷ. Ngoài tinh không, tứ đại chiến tướng kết trận pháp dùng hồ lô phun sương mù tạo Vụ thú truy tìm hồn thứ ba, hủy diệt sinh mạng trên đại lục hoang phế để Vụ thú hấp thu khí tức luân hồi, xác nhận hồn thứ ba từng luân hồi tại đây rồi hướng sang La Thiên. Chiến lão quỷ đi theo phía sau, nhận định hồn thứ ba có lẽ đang ở La Thiên. Đạo nhân bảy màu đã lục soát gần hết Côn Hư không tìm ra đầu mối, dùng giọt máu huyết mạch chúng sinh làm công cụ dò tìm, cất bước tới Triệu Hà tiếp tục. Vương Lâm triệu Thanh Thủy tới, Thanh Thủy chủ động thừa nhận bản thân là do một phách của Thất Thải Tiên Tôn biến thành, toàn lực hỗ trợ. Vương Lâm cam kết bảo vệ thất phách, dùng Hồn Phiên mặt quỷ cắn nuốt cả hai, đưa thần thức vào thời vạn cổ khi Thất Thải Tiên Tôn bị phân chia ba hồn bảy phách để truy tìm hồn thứ ba."},{"chuong":1650,"tieuDe":"Thất Phách Tương Ứng","tomTat":"Vương Lâm dùng Thanh Thủy dẫn đường, mượn tấm buồm mặt quỷ chủ động tiến vào huyễn cảnh của động phủ giới để truy tìm bí ẩn từ vạn cổ năm trước. Tầng huyễn cảnh thứ nhất tái hiện cảnh Thanh Thủy năm xưa tàn sát hoàng cung phàm gian đã hại gia đình hắn, giết hoàng đế và mấy trăm tu sĩ thượng cổ. Vương Lâm đồng cảm sâu sắc vì bóng lưng nhuộm máu của Thanh Thủy giống chính hắn ở Đằng gia năm đó, an ủi Thanh Thủy rồi kích hoạt chuyển sang tầng hai. Tầng hai tái hiện cảnh thiên địa sơ khai tại trung tâm động phủ giới: Liên Đạo Phi gầm rống khiến thiên đạo trọng thương sụp đổ, đồng thời oanh kích Thất Thải Tiên Tôn vỡ nát hoàn toàn, ba hồn bảy phách tán ra bốn phương. Vương Lâm quan sát bảy phách bảy màu tiến vào luân hồi và nhận ra danh tính bốn phách đầu: phách đỏ đậm chủ sát là Thanh Thủy, phách xanh chứa toàn bộ tu vi là Tư Đồ Nam, phách cam chứa chính khí lương tri là Thanh Lâm, phách vàng đại biểu khí vận cơ duyên là Tham Lang. Vương Lâm minh ngộ rằng thiên tư kinh người của Tư Đồ Nam chính vì hắn là phách của Thất Thải Tiên Tôn."},{"chuong":1651,"tieuDe":"Tam Hồn Quy Vị","tomTat":"Thất phách của Thất Thải Tiên Tôn lần lượt tiêu tán — phách thứ năm (lục, bản năng phân thân) hé lộ bên trong là Tán Linh Thượng nhân, phách thứ sáu (lam, tình cảm yêu hận với Phàn San Mộng) hé lộ là Mộc Băng Mi khiến Vương Lâm tái nhợt, phách thứ bảy (tím, điên cuồng phẫn nộ) chưa rõ danh tính. Tam hồn bay đi ba hướng: hồn thứ nhất hóa thành đạo nhân bảy màu nhận toàn bộ thần thông Tiên Tôn bay ra giới ngoại, hồn thứ hai luân hồi thành mãnh thú gặp Chiến lão quỷ đang độ huyền kiếp thất bại — là tiên duyên của Chiến lão quỷ. Vương Lâm truy đuổi hồn thứ ba xuyên nhiều tinh vực, chứng kiến nó luân hồi nhiều lần thành mãng xà, thư sinh, đại thụ, tu sĩ Kết Đan, rồi thành phàm nhân Tô Đạo tại Chu Tước Tinh trở thành đại nho Triệu quốc — hé lộ nhân quả sâu xa trong Mộng Đạo khi Tô Đạo đã nhận Vương Lâm làm đệ tử. Cuối cùng hồn thứ ba tại Thanh Linh tinh luân hồi thành cá mấy trăm lần trong cùng con sông, chờ đợi cho tới khi ngư ông câu được và nói vợ sắp sinh — ám chỉ hồn thứ ba sắp đầu thai thành con ngư ông."},{"chuong":1652,"tieuDe":"Hồn Thứ Ba Là Hắn","tomTat":"Vương Lâm quan sát kiếp luân hồi cuối cùng của hồn thứ ba: ngư ông Tạ Đông Minh bắt cá trở về căn nhà cỏ trong rừng trúc nơi thê tử Tố Nhi đang mang thai. Đêm mưa bão, Tố Nhi sinh khó, Tạ Đông Minh đấm tay vào vách trúc chảy máu tự bạch ba mươi ba năm thanh liêm, trách trời — cuối cùng mẫu tử bình an, đặt tên con là Tạ Thanh. Nghe tên này, Vương Lâm chấn động dữ dội: hồn thứ ba của Thất Thải Tiên Tôn chính là đệ tử Tạ Thanh của hắn. Hắn nhớ lại Tạ Thanh già nua leo núi cầu đạo trên Thanh Linh Tinh, câu nói năm xưa về con cá trong nước — giờ mới hiểu hồn thứ ba đã luân hồi hàng trăm kiếp làm cá. Vương Lâm ngộ ra nhân quả tuần hoàn: điểm hóa Tạ Thanh kết nhân quả, Mộng Đạo gặp Tô Đạo, hiện thực Tạ Thanh là đệ tử hắn nhưng trong Mộng Đạo hắn lại là đệ tử Tô Đạo. Đối mặt câu hỏi giết hay không giết hồn thứ ba, Vương Lâm lùi ba bước phá sập toàn bộ huyễn cảnh — kiếp cuối sụp đổ, trở về cạnh Thanh Thủy rồi hoàng cung huyết sắc cũng tan, mặt quỷ nuốt cả hai — cuối cùng cả hai đồng thời mở mắt tỉnh lại trong động phủ giới trên đỉnh núi, Vương Lâm sắc mặt tái nhợt nói: hồn thứ ba là hắn."},{"chuong":1653,"tieuDe":"Hồn Thứ Ba Là Hắn","tomTat":"Thanh Thủy rời đi sau khi nhìn Vương Lâm, hiểu hắn đang do dự vì hồn thứ ba chính là đệ tử Tạ Thanh. Vương Lâm ngồi trên đỉnh núi tiên giới, thống khổ không thể tự tay ngăn tam hồn dung hợp. Hắn suy luận phách thứ bảy không nằm trong thiên đạo hiện tại vì U Minh thú nuốt Thiên Vận Tử mà không có khí tức phách thứ bảy, chứng minh thiên đạo chưa hoàn chỉnh, nghi Thiên Vận Tử áo xám có thể mang phách thứ bảy. Liệt kê sáu phách đã biết nhưng rơi vào mâu thuẫn: bốn phách có hồn phách vận mệnh trong thiên kiếp luân hồi, lẽ ra không nên nếu họ chỉ là phách của Thất Thải Tiên Tôn. Huyền La Đại Thiên Tôn điểm một ngón tay đưa ý niệm vào đầu Vương Lâm, giúp hắn giác ngộ khái niệm biến số — bốn phách qua luân hồi đã trở thành thân thể chính thức tách biệt hoàn toàn, còn Thanh Thủy và Tư Đồ Nam chưa xảy ra biến số. Vương Lâm nhận ra nếu nắm được lực lượng biến số có thể khiến hồn thứ ba Tạ Thanh độc lập, ngăn tam hồn dung hợp, nhưng chưa hiểu rõ bản chất. Huyền La tiết lộ thiên đạo xuất hiện đầu tiên ở Cổ Thần cảnh, Cửu dương cũng đang tìm bước tiến tiếp theo nhưng chưa ai làm được. Bình minh, Vương Lâm một bước biến càn khôn tới La Thiên Tinh Vực, dựa nhân quả sư đồ cảm nhận Tạ Thanh đang ở tu chân tinh phía đông La Thiên rồi hướng đó mà đi. Cùng lúc, tứ đại chiến tướng và Chiến lão quỷ theo Vụ thú tìm kiếm trong La Thiên, còn đạo nhân bảy màu từ nơi tiếp giáp Triệu Hà bước ra, không có đầu mối, bắt đầu tìm kiếm."},{"chuong":1654,"tieuDe":"Không Diệt Sơ Hiện","tomTat":"Ở phía đông La Thiên, trên tu chân tinh hoang phế, Vương Lâm tìm đến u cốc hoa lan gặp lại đệ tử Tạ Thanh. Tạ Thanh tiết lộ bản thân chính là hồn thứ ba của Thất Thải Tiên Tôn, nhưng khẳng định bản ngã là Tạ Thanh chứ không phải Tô Đạo hay Thất Thải Tiên Tôn. Hắn đã dùng hồn tu lực nhiều năm ngưng tụ ba đạo phong ấn: phong ấn thứ nhất chặn luân hồi hồn thứ ba khi chết và mở trung tâm động phủ cùng đại môn thông Tiên Cương đại lục; hai phong ấn còn lại phối hợp lực Tiên Cương phong ấn hồn thứ nhất và hồn thứ hai. Tạ Thanh cũng tiết lộ trong bảy phách còn hai phách cực kỳ quan trọng với Vương Lâm. Vương Lâm đau đớn khi nhận ra Tạ Thanh sắp chết, phẫn nộ thề cả đời muốn diệt trời; toàn thân bộc phát khí thế ngưng tụ thành thanh kiếm hư ảo mang khí tức Không Diệt lần đầu sơ hiện, khiến Huyền La Đại Thiên Tôn đi phía sau kinh hãi. Tạ Thanh tự nguyện nhắm mắt, nở nụ cười giải thoát, khí tuyệt thân vong. Vương Lâm thu lấy hồn thứ ba từ thất khiếu Tạ Thanh; khi hồn tỉnh giấc, thiên địa biến sắc, tứ đại tinh vực ầm vang, giới ngoại cũng kinh thiên."},{"chuong":1655,"tieuDe":"Động Phủ Mở Ra","tomTat":"Toàn bộ Thái cổ Tinh Thần giới ngoại bùng nổ chấn động kinh hoàng, sương mù cuồn cuộn bao phủ khắp tinh không, vô số tấm đá khổng lồ từ tám phương ngưng tụ lao về La Thiên Tinh Vực. Vương Lâm đứng trong sơn cốc đầy thu lan, chứng kiến đệ tử Tạ Thanh gọi tiếng sư tôn cuối cùng rồi mỉm cười qua đời, phẫn nộ với thiên ý trêu người, tuyên bố sẵn sàng hủy diệt thiên không. Hồn thứ ba của Thất Thải Tiên Tôn xuất hiện trong thi thể Tạ Thanh, Vương Lâm coi đó là đệ tử chứ không phải Thất Thải Tiên Tôn, thề giúp ngưng tụ thành hồn rồi dung nhập hồn thứ ba vào cơ thể, kích hoạt trung tâm động phủ chính thức mở ra. Đạo nhân bảy màu phẫn nộ vì có người lấy hồn thứ ba trước, điên cuồng lao tới. Chiến lão quỷ lộ hư ảnh khổng lồ bên ngoài thân — một trong tam hồn Thất Thải Tiên Tôn, quyết liều chết nếu đạo nhân bảy màu đạt được hồn. Chưởng Tôn hoảng sợ lao về giới nội, tứ đại chiến tướng điên cuồng lao tới, các tiên phi hóa cầu vồng bay vào, đệ tử Thất Đạo Tông thoát viễn cổ tiên vực, lão già họ Mã dẫn nhóm Ngũ Hành tinh tiến về La Thiên. Lam Mộng Đạo Tôn truyền âm cho Tư Đồ Nam và Thanh Thủy trong tiên giới, nói không có huyết mạch Tiên Cương đại lục nên không thể tự vào trung tâm động phủ, muốn mượn hồn phách hai người."},{"chuong":1656,"tieuDe":"Nhân Tụ","tomTat":"Bên ngoài tu chân tinh của Vương Lâm, vô số mảnh đá từ tinh không lao tới ngưng tụ thành đại môn trung tâm động phủ — chính là cánh cửa từng bị thiên đạo đánh vỡ ở chiến trường ngoại vực Chu Tước Tinh, nay do hồn thứ ba thức tỉnh mà tái tạo hoàn chỉnh, tỏa cơn lốc chấn động ngăn mọi người tiếp cận. Vương Lâm cúi nhìn thi thể Tạ Thanh quỳ trong sơn cốc, bi ai dùng thu lan an táng nàng thành ngôi mộ, hứa sẽ tới đánh thức, từ đó mỗi mùa thu hoa lan ngập tràn tu chân tinh vô danh. Đạo nhân bảy màu và Chiến lão quỷ — hai hồn của Thất Thải Tiên Tôn — lần lượt chiêu dụ Vương Lâm: một bên cam đoan an toàn cho tiên giới và mở đường Tiên Cương đại lục, một bên hứa cho thê tử sống lại và tặng toàn bộ động phủ giới, chỉ đổi lấy hồn thứ ba; Vương Lâm không đáp, không động tâm. Quần hùng lần lượt tề tụ — tứ đại chiến tướng, Chưởng Tôn, các tiên phi giới ngoại, đệ tử Thất Đạo Tông, nữ tử Triệu Hà, Lam Mộng Đạo Tôn, đám người Ngũ Hành tinh do lão già họ Mã cầm đầu — tất cả bị cơn lốc ngăn cản, tụ tập bên ngoài đại môn. Đợi mọi người tới đủ, Vương Lâm mở mắt bình tĩnh tuyên bố mọi người đều muốn hồn này rồi giơ tay phải phô bày hồn thứ ba lấp lóe u quang trước mặt hàng loạt cường giả."},{"chuong":1657,"tieuDe":"Cuộc Săn","tomTat":"Sau khi hồn thứ ba xuất hiện, tất cả tu sĩ xung quanh đều nhìn chằm chằm với ánh mắt tham lam. Vương Lâm tuyên bố đây là cuộc săn hồn — hoặc hắn là thợ săn, hoặc họ là thợ săn, rồi dùng hồn thứ ba mở đại môn động phủ mà chỉ hắn mới mở được. Cơn lốc kinh thiên đẩy lùi tất cả trừ Vương Lâm, hắn bước vào khi cửa mới mở ba phần. Đạo nhân bảy màu lao vào đầu tiên, Chiến lão quỷ theo sát, rồi lần lượt Chưởng Tôn, Lam Mộng Đạo Tôn (mượn hồn mà vào dù không có huyết mạch tiên cương), các tu sĩ còn lại, nhóm Ngũ Hành tinh, và cuối cùng Huyền La Đại Thiên Tôn xuất hiện từ hư vô tuyên bố khảo sát Vương Lâm sẽ chấm dứt ở đây. Bên trong, Vương Lâm nhận ra trung tâm động phủ chính là cánh cửa thông tới Tiên Cương đại lục, và thông qua trí nhớ hồn thứ ba hắn biết bí mật sát chiêu cuối cùng của Thất Thải Tiên Tôn mà không ai khác biết — cần tích đủ sát lục mới dùng được. Hắn lên kế hoạch dùng ba trăm tàn nguyên giới để giết đối thủ yếu, tích lũy sức mạnh cho trận quyết chiến cuối cùng. Vương Lâm bước vào giọt sương trên đóa hoa khổng lồ, phát hiện bên trong là một vùng tinh không tỏa ánh sáng như ngọc, tràn ngập tinh vân."},{"chuong":1658,"tieuDe":"Ba Trăm Tàn Giới","tomTat":"Vương Lâm dung nhập vào đại đỉnh trung tâm động phủ, khuôn mặt hiện trên mặt đỉnh bị hắc khí bao quanh. Bên trong hắn phát hiện một đóa hoa vàng năm cánh khổng lồ mang ba trăm giọt sương, mỗi giọt là một thế giới thất bại khi Thất Thải Tiên Tôn sáng tạo động phủ giới, được luyện hóa thành lực phòng hộ chỗ bế quan. Nhờ ký ức hồn thứ ba, Vương Lâm hiểu rõ ba trăm tàn giới chia ba loại: tiên thú biến dị, phàm nhân sinh sôi, và không sinh linh. Hắn xác nhận mình đang ở tàn giới loại ba, tản thần thức lục soát chín tu chân tinh nhưng không tìm được gì, sau đó phát hiện sóng gợn vô hình bí ẩn từ ngọn núi trọc hình kiếm trên tu chân tinh thứ năm. Hắn thử truyền thần niệm để định quy tắc nhưng tàn giới không đủ lực ngưng tụ, quyết định thay đổi cách thức. Bên ngoài, đại môn động phủ mở hoàn toàn, đạo nhân bảy màu bay vào đại đỉnh trước, Chiến lão quỷ theo sau. Chưởng Tôn vừa bước tới đống đổ nát thì phát hiện nguy hiểm, lập tức ẩn thân. Lam Mộng Đạo Tôn đi tới sau, mỉm cười thản nhiên cất bước dung nhập vào đại đỉnh mà đống đổ nát không phản ứng, khiến Chưởng Tôn đang ẩn thân nhíu mày."},{"chuong":1659,"tieuDe":"Định Quy Tắc","tomTat":"Tứ đại chiến tướng cùng đệ tử Thất Đạo Tông và các tiên phi tiến vào khu vực đống đổ nát trước đại đỉnh, nhưng tơ máu đỏ bùng phát ngăn cản hầu hết mọi người, chỉ một lão già viễn cổ tiên nhân của Thất Đạo Tông may mắn vượt qua và xông vào đại đỉnh, trong khi Chưởng Tôn ẩn thân quan sát với nụ cười lạnh. Lão già chọn một giọt sương dung nhập, xuất hiện trong tàn giới của Vương Lâm qua dòng xoáy. Vương Lâm kích hoạt quy tắc cấm phi hành đã thiết lập sẵn trong tàn giới khiến lão mất năng lực bay, rồi dùng huyết kiếm xuyên mi tâm giết chết, đánh nát cả nguyên thần. Sau đó hắn dùng hồn thứ ba bắt quyết, triệu hồi một cánh tay đen kịt bao phủ hắc khí chụp lấy toàn bộ huyết mạch và thần hồn của lão già để tế cho một thân thể bí ẩn. Năm ngày tiếp theo Vương Lâm ôm cây đợi thỏ, vừa cảnh giác vừa đắm chìm dung hợp ký ức hồn thứ ba. Đến ngày thứ sáu, ba tiên nhân Thất Đạo Tông gồm một Không Niết sơ kỳ và hai thiên nhân ngũ suy xuất hiện qua dòng xoáy, Vương Lâm xác nhận không phải đạo nhân bảy màu hay Chiến lão quỷ liền ra tay phục kích, dùng huyết kiếm và thần thông giết sạch cả ba trong chưa tới ba nhịp thở, kẻ Không Niết sơ kỳ định đốt một cây hương cầu viện nhưng không kịp. Ngay sau đó một dòng xoáy mới xuất hiện trong tinh không, bên trong có thân ảnh mơ hồ của một nữ tử chưa rõ danh tính."},{"chuong":1660,"tieuDe":"Tử Hà","tomTat":"Vương Lâm nhận ra nữ tử trong dòng xoáy chính là Tử Hà — thất phi trung thành nhất của Thất Thải Tiên Tôn, người sở hữu Tỵ Thiên Quan. Hai bên giao chiến thăm dò: Tử Hà triệu phượng hoàng tím đối kháng huyết kiếm, ngang sức ngang tài. Vương Lâm bố trí kế tâm lý nhiều tầng — đầu tiên giả vờ vội vã rời đi như bị thương, khi Tử Hà phóng phi kiếm tím thử sức thì cố ý bộc phát sáu đạo bổn nguyên chấn nát phi kiếm rồi cười lạnh bỏ đi. Tử Hà suy luận ngược rằng chỉ người bị thương thật mới phô trương để che giấu, quyết không truyền tin gọi viện binh vì sợ tứ đại chiến tướng đoạt mất hồn thứ ba, bước ra khỏi dòng xoáy truy đuổi. Dòng xoáy tiêu tán, quy tắc tàn giới phát tác khiến thân thể nàng rơi vụt xuống. Vương Lâm lập tức quay người, huyết kiếm vô thanh vô tức đánh thẳng mi tâm Tử Hà, máu đen phun ra từ ngực nàng, y phục rách nát, trọng thương."},{"chuong":1661,"tieuDe":"Đánh Cuộc","tomTat":"Vương Lâm dùng huyết kiếm xuyên ngực Tử Hà, thi triển liên hoàn sáu đạo bổn nguyên đánh trọng thương cả thân thể lẫn nguyên thần nàng, rồi thi triển Định thân thuật và chín chỉ phong ấn đại thành để bắt sống, thu nàng vào tay áo vì trên người nàng còn nhiều thứ khiến hắn hứng thú. Toàn bộ chiến đấu không quá mười nhịp thở. Sau đó Vương Lâm rời tàn giới trước, xông qua dòng xoáy vào một tàn giới khác. Nơi đây Bạch Hổ chiến tướng là người đến trước đã thiết lập toàn bộ quy tắc, đang lợi dụng cuộc đại chiến trăm vạn quân trên tu chân tinh thứ ba để hấp thu sát khí. Nam tử trung niên tầng thứ bảy Ngũ Hành tinh cũng bị kẹt trong quy tắc, hư ảo hóa đối diện Bạch Hổ. Vương Lâm dùng thần thức quét toàn tinh không, nhận ra quy tắc đã tồn tại, chủ động đứng yên giữ mình ngoài quy tắc. Hắn giả vờ tạo dòng xoáy rời đi để thử phản ứng Bạch Hổ, từ đó tìm ra đáp án. Bạch Hổ chiến tướng đề nghị đánh cuộc: Vương Lâm bại thì mất hồn thứ ba, thắng thì Bạch Hổ lấy huyết mạch thề theo lời thề Tiên Cương đại lục cam tâm làm nô bộc vạn năm. Vương Lâm bề ngoài bình tĩnh nhưng khóe miệng lộ nụ cười."},{"chuong":1662,"tieuDe":"Ván Cờ","tomTat":"Vương Lâm phân tích quy tắc tàn giới thứ ba do Bạch Hổ chiến tướng thiết lập — đây là ván cờ trăm vạn đại quân, lực lượng cả giới áp chế chín thành huyết mạch người bên trong, người có huyết mạch tiên nhân giữ sức mạnh thể chất đóng vai tướng, người không có chỉ làm binh. Vương Lâm nhận ra Đạo Cổ truyền thừa của mình cũng có lực lượng huyết mạch, phối hợp tu vi còn mạnh hơn Bạch Hổ. Khi Vương Lâm tiến vào tàn giới, huyết mạch bộc phát khiến lực áp chế phải phân tán cho ba người, phá vỡ tính toán của Bạch Hổ, đồng thời nới lỏng áp chế cho nam tử Ngũ Hành tinh. Trên chiến trường, Vương Lâm giết địch binh không ngừng, tích hắc khí ngưng tụ thành giáp đen toàn thân rồi hắc mã, diệt mười hắc giáp binh của Bạch Hổ trong nửa nén hương, cưỡi ngựa lao thẳng về phía tướng lãnh bạch giáp. Bạch Hổ chấn động buộc phải lui kéo giãn khoảng cách. Ở nơi khác, đạo nhân bảy màu đã đi qua gần trăm giới truy tìm Vương Lâm, cuối cùng cảm nhận được khí tức của hắn ở không xa, vô cùng kích động tiếp tục truy đuổi, tạo áp lực thời gian cấp bách cho ván cờ."},{"chuong":1663,"tieuDe":"Một Đao Chờ Sẵn","tomTat":"Trong giới cờ, Vương Lâm hóa chiến tướng hắc giáp đối đầu chiến tướng bạch giáp của Bạch Hổ Thánh Hoàng. Lần va chạm đầu tiên, trường đao đối trường thương cùng hủy, hai ngựa va đầu chết, hư ảnh Đạo cổ Vương Lâm hiện ra. Bạch Hổ từ chối nhận thua, tự đấm ngực phun máu rồi phóng ngàn giọt huyết khí giết gần mười vạn binh lính không phân địch ta để tái tạo lực lượng. Vương Lâm thay vì giết binh lấy khí tức, chọn thôn phệ chiến tướng kim giáp yếu nhất bằng bản năng thôn hồn, lập tức tăng mạnh, tái tạo giáp mũ giáp, dưới thân ngưng tụ hắc long. Quyết chiến lần hai, Vương Lâm một đao kèm hư ảnh Đạo cổ chẻ đôi chiến tướng bạch giáp từ mi tâm, tuyên bố thu Bạch Hổ làm nô bộc. Ngay sau đó bổn tôn Vương Lâm cảm nhận nguy cơ mãnh liệt, hợp nhất với phân thân, nuốt toàn bộ khí tức bạch giáp, ngưng tụ đại đao đạt lực lượng giới hạn tàn giới rồi giơ đao chờ sẵn, đồng thời tay trái bắt quyết hóa ô lửa nhỏ rồi biến mất."},{"chuong":1664,"tieuDe":"Bảy Màu Đã Tới","tomTat":"Vương Lâm đứng giữa cơn lốc hắc khí ngưng tụ toàn bộ tu vi vào một đao, uy áp trấn áp Bạch Hổ chiến tướng và tu sĩ Ngũ Hành tinh khuất phục. Đạo nhân bảy màu xé dòng xoáy xâm nhập tàn giới, cảm nhận khí tức Vương Lâm và tuyên bố tìm được hắn. Vương Lâm chém một đao mượn quy tắc cả tàn giới, hấp thu cơn lốc cùng toàn bộ binh lính bàn cờ, đánh tan quy tắc Bạch Hổ khiến Bạch Hổ phun máu, đường đao xuyên tinh không vạn trượng chém thẳng đạo nhân bảy màu. Đạo nhân triệu Thất Thải Đạo Liên — hoa sen bảy cánh bảy màu — co rút thành nụ hoa phòng ngự nhưng vẫn bị đánh vỡ hai cánh, lực trùng kích phá hủy bảy trong chín tu chân tinh và hình thành hố đen. Đạo nhân phản công bằng năm cánh hoa còn lại kết hợp đích thân lao tới, Vương Lâm dùng Phần Giới Cổ Tán đã bí mật huyễn hóa sẵn thành ô lửa chặn đỡ, nương lực trùng kích lùi ba bước dung hợp dòng xoáy thoát thân. Đạo nhân nhảy vào dòng xoáy chụp hụt, thề đuổi giết rồi đuổi theo. Tàn giới hủy diệt hoàn toàn, Bạch Hổ chiến tướng nhận mệnh lệnh đầu tiên từ Vương Lâm: bắt tu sĩ Ngũ Hành tinh vì có chỗ quan trọng cần dùng."},{"chuong":1665,"tieuDe":"Tâm Cơ","tomTat":"Vương Lâm bị đạo nhân bảy màu truy kích liên tục xuyên ba trăm tàn giới, dùng thuật Tê Thiên xé hư không phá dòng xoáy xóa dấu vết. Hắn phát hiện một tàn giới có mãnh thú ngủ say với khí tức kinh người, ghi nhớ vị trí rồi tiếp tục chạy. Đạo nhân bảy màu nhận ra kế phá tấm màn ngăn cách của Vương Lâm, âm thầm củng cố tấm màn bằng ánh sáng bảy màu định tương kế tựu kế. Huyền La Đại Thiên Tôn theo dõi toàn bộ cuộc truy kích từ phía sau, quyết định không ra tay mà coi đây là lần khảo nghiệm cuối cùng đối với Vương Lâm. Vương Lâm bày kế trong kế: kế thứ nhất cố ý lộ việc phá tấm màn ngăn cách để đối phương buông lỏng cảnh giác, kế thứ hai dùng tấm buồm mặt quỷ biến thành tu chân tinh tầm thường kết hợp thói quen tiềm thức do lặp hành động cả trăm lần. Tất cả kẻ truy kích kể cả Chiến lão quỷ đều bị lừa đi hướng sai. Huyền La Đại Thiên Tôn kinh ngạc khen Vương Lâm là rồng trong cõi người. Vương Lâm đi ngược hướng quay lại tàn giới mãnh thú, quyết định dùng Tam mệnh thuật phản kích. Chương cũng hé lộ ba trăm tàn giới tồn tại nhờ đóa hoa kỳ bảo Thất Thải Tiên Tôn lấy từ tiên giới, bí mật chỉ hắn biết."},{"chuong":1666,"tieuDe":"Thất Phục Sát","tomTat":"Vương Lâm ngồi trên tu chân tinh sa mạc cát vàng cuối cùng trong tinh vực, phát hiện Mục Ngư — loài rắn đất dài ngàn trượng từ Tiên Cương, đã hấp thu linh khí sơn mạch và nuốt hết các tu chân tinh khác trong tinh vực. Hắn nhớ lại năm xưa Thất Thải Tiên Tôn (hồn thứ ba) đã đem Mục Ngư nhỏ vào ba trăm tàn giới nuôi nhưng vì thân thể phân chia nên không lấy ra được. Vương Lâm quyết định lợi dụng địa thế này thiết lập bảy tầng mai phục kinh thiên: Phần Giới Cổ Tán vô hình che phủ, Thất Thải Đạo Thương cắm xuống đất, bổn tôn Đạo Cổ triệu hồi Khai Thiên Phủ toàn lực, buồm mặt quỷ hút gần nửa máu tạo ảo cảnh, U Minh thú ẩn sương mù, vòng máu kích Mục Ngư dưới lòng đất, và cây cung Lý Quảng triệu hồi bằng huyết mạch tiên nhân cuối cùng. Tiêu hao cực lớn tinh lực và máu tươi, hắn đốt hương đen phát tín hiệu rồi khống chế Tử Hà truyền thần niệm vào ngọc giản truyền âm làm mồi nhử. Mục tiêu của Vương Lâm không phải giết mà là trọng thương một trong hai kẻ thù — đạo nhân bảy màu hoặc Chiến lão quỷ — nhằm phá vỡ thế cân bằng lực lượng giữa hai bên, tạo cơ hội cho kẻ còn lại."},{"chuong":1667,"tieuDe":"Tiểu Quyết Chiến","tomTat":"Vương Lâm đốt chiến hương dẫn dụ toàn bộ đệ tử Thất Đạo Tông ở giới ngoại, đồng thời ngọc giản Tử Hà vỡ nát triệu tập ba chiến tướng Thanh Long, Huyền Vũ, Chu Tước. Đạo nhân bảy màu truy kích Vương Lâm xuyên giới nhưng mất dấu, nổi giận thề giết rồi theo hương tới tu chân tinh. Chiến lão quỷ cũng bỏ dở việc theo dõi đám tu sĩ, quay đầu tìm tới. Chưởng Tôn và Lam Mộng Đạo Tôn xuất hiện mệt mỏi sau khi giao chiến trong ba trăm tàn giới, nhìn nhau hàn ý. Phân thân Vương Lâm ngồi trên cát vàng cầm cung Lý Quảng, lấy hồn thứ ba từ mi tâm phóng thích khí tức làm mồi nhử, tuyên bố ai tới gần một trượng được lấy hồn. Đạo nhân bảy màu, Chiến lão quỷ và các tu sĩ không cưỡng nổi đều lao vào tinh cầu. Vương Lâm kích hoạt tầng mai phục thứ nhất — Phần Giới Cổ Tán — lần đầu tiên bất chấp tất cả toàn lực thi triển, cổ tán khổng lồ biến bầu trời thành biển lửa đóng cửa quan, dung nhập hỏa bổn nguyên thiêu đốt tâm thần. Thu ba thành giết ba đệ tử Thất Đạo Tông chưa đạt bước thứ ba, thu sáu thành khiến tam đại chiến tướng sắc mặt đại biến. Vương Lâm cố ý ngăn Lam Mộng Đạo Tôn ở ngoài tán để bảo vệ."},{"chuong":1668,"tieuDe":"Phục Sát Động","tomTat":"Vương Lâm thi triển Phần Giới Cổ Tán đạt cực hạn tám thành, sức sống tuôn ra điên cuồng khiến toàn thân già nua quá nửa, gây tổn thương nặng nề cho toàn bộ đối thủ. Đạo nhân bảy màu nhờ cũng được truyền thừa thuật này nên là người đầu tiên thoát biển lửa lao tới, nhưng bị trường thương bảy màu của Vương Lâm phá tan hoàn toàn đài sen bảy màu. Bổn tôn Vương Lâm ngàn trượng hiện ra cầm Khai Thiên Phủ giáng xuống, cố ý để búa vỡ bạo phát uy lực, bổn tôn sụp đổ nhưng nhờ Đạo Cổ bất diệt thể dung hợp phân thân hồi phục. Chiến lão quỷ thoát biển lửa lao tới hồn thứ ba thì bị Quỷ Kiếm Huyết Phàm vây khốn mê man bất động. Vương Lâm triệu hồi U Minh Thú nuốt hàng loạt đệ tử Thất Đạo Tông và lục phi, khiến đạo nhân bảy màu hoảng sợ khoảnh khắc. Cuối cùng hắn vỗ tay lên đất dùng mật thuật Bạch Hổ kết hợp phương pháp thao túng lực lượng đệ nhị Chu Tước kích thích Mục Ngư biến dị thức tỉnh, vòng tròn máu nổ tung bao vây bảy màu, mặt đất tu chân tinh rung chuyển cát vàng dấy ngợp trời."},{"chuong":1669,"tieuDe":"Thất Thải Kiếp","tomTat":"Trên tu chân tinh phủ đầy cát vàng, mãnh thú Mục Ngư — kỳ thú Tiên Cương hai mắt vĩnh viễn nhắm chặt, tương truyền mở mắt thiên địa biến sắc — lần lượt lao ra từ lòng đất tấn công đạo nhân bảy màu. Bảy màu thi triển thần thông Lục bạt sơn hề triệu hoán cánh tay khổng lồ lôi con Mục Ngư thứ nhất ném xa khiến nó trọng thương, nhưng ngay sau đó tám con Mục Ngư khác mỗi con dài mấy vạn trượng đồng loạt xuất hiện vây đánh. Vương Lâm nắm thời cơ kéo cung Lý Quảng bắn tiễn thứ nhất xuyên qua hào quang bảy màu đâm trúng ngực đối thủ, nhưng bảy màu kịp túm đuôi tên nên thân thể không bị xuyên thủng. Sức công kích khiến tu chân tinh sụp đổ vỡ vụn, tam đại chiến tướng bị gợn sóng đánh trúng đồng loạt phun máu, Chưởng Tôn kinh hãi lui lại vì đã bị mũi tên này giết chết hai lần. Bảy màu dữ tợn rút mũi tên khỏi ngực, tám con Mục Ngư lần đầu hé mở đôi mắt lộ hắc quang, khí thế tăng vọt. Mũi tên trong tay bảy màu tiêu tan tự quay về dây cung, Vương Lâm lập tức bắn tiễn thứ hai. Đám tu sĩ Ngũ Hành Tinh do lão già họ Mã cầm đầu đứng xa quan sát, lần đầu chứng kiến cung Lý Quảng cực kỳ chấn động; Vân Dật Phong tự thấy may mắn vì ở Ngũ Hành Tinh không bức Vương Lâm dùng cung, nhận định bản thân hoàn toàn không có khả năng chống cự."},{"chuong":1670,"tieuDe":"Đạo Phi Xuất Hiện","tomTat":"Vương Lâm bắn tiễn thứ hai từ cung Lý Quảng, tám con Mục Ngư phát động thiên phú mở mắt biến hóa thành tám mũi tên giả tạo chân giả lẫn lộn. Mũi tên thật xuyên qua hào quang bảy tầng, xuyên thủng ngực đạo nhân bảy màu gây trọng thương. Đạo nhân bảy màu điên cuồng bộc phát tu vi, thi triển thần thông mạnh nhất — chín mặt trời chói lọi. Vương Lâm cạn kiệt sức lực bắn tiễn thứ ba và cũng là cung cuối cùng, va chạm chín mặt trời nổ tung tạo sức mạnh hủy diệt kinh thiên, phá hủy ba trăm tàn giới, Thanh Long chiến tướng bị sức mạnh chạm phải tử vong tại chỗ. Vương Lâm đã chuẩn bị từ trước, triệu hồi Liên Đạo Phi từ không gian trữ vật ra làm lá chắn — người điên có tiên nhân bất diệt thể hoàn chỉnh, chắn toàn bộ lực hủy diệt mà lông tóc không hư tổn. Liên Đạo Phi nửa tỉnh nửa mê gào thét sẽ mách ca ca, sự xuất hiện của hắn khiến toàn trường chấn động: đạo nhân bảy màu lần đầu tiên bỏ chạy, Chưởng Tôn suýt quỳ sụp gọi chủ nhân, mọi người khiếp sợ. Đạo nhân bảy màu lộ mưu đồ thật — hắn muốn dùng cung Lý Quảng để dụ Liên Đạo Phi ra và để Vương Lâm đả thương Chiến lão quỷ, vì cả hắn lẫn Chiến lão quỷ đều không hoàn chỉnh nên không dùng được cung. Huyền La Đại Thiên Tôn thu lấy Mục Ngư thứ năm và nhận ra người điên chính là Liên Đạo Phi, đệ đệ của Liên Đạo Chân."},{"chuong":1671,"tieuDe":"Đông Lâm Tông","tomTat":"Người điên chống đỡ lực hủy diệt từ ba trăm giới sụp đổ rồi lăn ra ngủ. Vương Lâm kịp thu ba con Mục Ngư nhưng mất sáu con vào tay Huyền La Đại Thiên Tôn, phát hiện đặc tính đôi trống mái khí tức tương liên. Chiến lão quỷ xuất hiện do dự giữa đuổi Vương Lâm và truy kích đạo nhân bảy màu bị trọng thương. Vương Lâm hư trương thanh thế bằng lời thách thức về cung Lý Quảng, khiến Chiến lão quỷ chọn truy kích đạo nhân bảy màu — đúng phán đoán trong bảy tầng sát cục. Chưởng Tôn quan sát từ xa, nhìn ra mánh khóe Vương Lâm nhưng im lặng tính kế. Ba trăm giới vỡ vụn hoàn toàn, Vương Lâm bị trọng thương tiến vào đệ nhị hoa của Ngũ hoa bát môn — thế giới hoàn toàn đóng băng do Thất Thải Tiên Tôn tạo dựa trên ký ức về tông phái Đông Lâm tông trên Tiên Cương đại lục. Tại đây hắn gặp nữ Cổ Thần Vân Na, thần trưởng lão Đông Lâm tông, người ẩn chứa tâm thần huyết cuối cùng của Diệp Mịch, nhận hắn là chủ nhân mới và đề nghị dung hợp tâm thần huyết để chữa thương."},{"chuong":1672,"tieuDe":"Tàn Thần Dục Đoạt","tomTat":"Vương Lâm cùng nữ Cổ Thần ở trong không gian đóng băng, phát hiện có kẻ xâm nhập, nữ Cổ Thần vung tay đóng băng toàn bộ thiên địa phong bế chúng. Nữ Cổ Thần điểm vào mi tâm ngưng tụ giọt nguyên thần huyết cuối cùng của Diệp Mịch trao cho Vương Lâm, đổi lấy lời hứa giúp nàng rời khỏi động phủ giới. Nàng tiết lộ được Diệp Mịch tạo ra từ máu huyết để bảo vệ Đông Lâm tông với vị trí thần trưởng lão, nhị vị trưởng lão Yêu và Ma đã tử vong trong giấc ngủ đóng băng. Vương Lâm hấp thu giọt máu, nguyên thần huyết Diệp Mịch hoàn toàn đầy đủ, thân thể tăng cường mạnh mẽ. Nguyên thần Diệp Mịch ngưng tụ thành thực chất rồi mưu đoạt xá, nhưng Vương Lâm có hồn huyết được cổ Tổ tán thành nên Diệp Mịch không thể đối kháng, sau ba canh giờ tiêu tán hoàn toàn thành một phần Đạo cổ truyền thừa. Thương thế Vương Lâm hoàn toàn khôi phục, đã có hơn phân nửa Đạo cổ truyền thừa nhưng còn thiếu mắt trái, trái tim hoặc cánh tay trái. Huyền La Đại Thiên Tôn ẩn trong thiên địa gia cố tầng băng mạnh hơn ngàn vạn lần để tranh thủ thời gian cho Vương Lâm, đồng thời nảy ý bồi dưỡng nữ Cổ Thần làm thị thiếp cho đệ tử duy nhất."},{"chuong":1673,"tieuDe":"Cánh Tay Trái Của Diệp Mịch","tomTat":"Vương Lâm hoàn tất dung hợp giọt máu Cổ Thần cuối cùng, Đạo Cổ lực tràn khắp toàn thân, tinh điểm trên mi tâm và hai mắt ngưng thật, u quang đậm hơn, ánh mắt thoáng chạm vào Huyền La Đại Thiên Tôn khiến đối phương ngạc nhiên. Hắn cảm ứng sự kêu gọi từ sâu trong tầng băng, nữ Cổ Thần cho biết đó là hậu sơn Đông Lâm tông — Đông Lâm Trì do Thất Thải Tiên Tôn dựa trí nhớ sáng tạo ra. Vương Lâm hứa sẽ giúp nữ Cổ Thần rời khỏi nơi này rồi bay tới vị trí kêu gọi. Xuyên qua tầng băng tới ngọn núi cao, phát hiện phía sau có hồ nước lớn đóng băng nửa trong suốt tỏa tiên khí, bên dưới là cánh tay trái khổng lồ của Diệp Mịch. Dùng huyết kiếm đâm nhưng bị bật lại, hồ băng dung hợp lực cánh tay nên tự phục hồi. Chuyển sang thi triển Đạo Cổ bất diệt chỉ phá băng suốt mấy canh giờ, giật tung nhiều khối băng, thu khối chứa lực lượng giống bổn nguyên vào không gian trữ vật, suy đoán Đông Lâm Trì thật có công hiệu nuôi dưỡng bổn nguyên. Cuối cùng lộ da tay cánh tay trái Diệp Mịch tỏa khí tức Đạo Cổ nồng đậm, đặt tay trái lên hấp thu ba ngày, cánh tay thu nhỏ hóa làn khói chui vào tay hắn — dung hợp thành công, nay đã có cả hai cánh tay Diệp Mịch. Huyền La Đại Thiên Tôn đứng trên bầu trời quan sát toàn bộ, cười cười với ánh mắt cổ quái."},{"chuong":1674,"tieuDe":"Lại Tới Cổ Mộ","tomTat":"Vương Lâm dung hợp hoàn toàn cánh tay trái Diệp Mịch từ khí tức trong hồ băng, tinh điểm tam tộc cổ biến hóa kịch liệt và mơ hồ xuất hiện hình ảnh tinh điểm thứ chín. Hắn dùng thuật Tê Thiên với sức mạnh hai tay xé đôi hồ băng và mặt đất, xuyên vào ngũ hoa bát môn qua khe nứt khổng lồ. Đi qua đệ tam hoa đã chết hoàn toàn, hắn từ bỏ kế hoạch mai phục vì Chiến lão quỷ đa nghi. Tiến vào đệ tứ hoa, Vương Lâm phát hiện thế giới bên trong chính là vùng đất cổ mộ nơi năm đó hắn đạt Đạo Cổ truyền thừa, do Thất Thải Tiên Tôn bố trí. Trên cây đinh bảy màu, các khuôn mặt đã tiêu tán quá nửa kể cả đạo nhân bảy màu, chỉ còn hai khuôn mặt cực rõ nét là Chiến lão quỷ và Vương Lâm. Hắn quyết định liều mạng xuống tầng hai cổ mộ để hấp thu trái tim Diệp Mịch, nếu thành công sẽ đạt Cổ Thần cửu tinh. Tam phi bay trong sương mù, nhận ra đây là nơi năm đó gặp Vương Lâm và được hắn trợ giúp, trong lòng muốn báo đáp. Huyền La Đại Thiên Tôn xác nhận đây là nơi Diệp Mịch tử vong, còn Thác Sâm ở đại điện cổ mộ bất ngờ mở mắt khi Vương Lâm tiến vào."},{"chuong":1675,"tieuDe":"Dĩ Ti Chi Khôi","tomTat":"Vương Lâm xâm nhập tầng một vùng đất cổ mộ, tránh đàn mãnh thú và dựa ký ức hồn thứ ba nhận ra khí tức kinh khủng ở tầng hai chính là Dĩ Ti Chi Khôi — sát chiêu cả đời Thất Thải Tiên Tôn tế luyện, đại thành sau khi giết Diệp Mịch. Hắn tiết lộ mỗi lần giết người đều dùng phương pháp trong ký ức hồn thứ ba để tế hồn, tạo liên lạc với Dĩ Ti Chi Khôi, và suy luận vùng đất cổ mộ có thể do Thất Thải Tiên Tôn tạo ra để nuôi dưỡng vật này. Vương Lâm tìm được truyền tống trận cổ xưa, bước vào tầng hai — nơi hồng quang bao trùm như địa ngục, phát hiện ngọn núi nơi Dĩ Ti Chi Khôi hóa hình đầu lâu khổng lồ phát tiếng rống kinh thiên. Bị tiếng gầm đẩy lùi ngàn trượng và trào máu, Vương Lâm nhận ra muốn khống chế phải giết thêm tu sĩ có đại thần thông tế hồn. Đệ tam phi Đường San theo u quang truyền tống trận cắn răng bước vào tầng hai, bị tiếng gầm tấn công, dùng kim môn chống đỡ nhưng liên tục bị phá vỡ. Vương Lâm hiện thân chặn dư âm cho nàng rồi lạnh lùng từ chối sự giúp đỡ, nhưng đệ tam phi đưa ra chuỗi hạt châu trên cổ tay do sư tôn ban tặng — có thể hóa thành bảy kim môn đồng thời — đề nghị giúp hắn tiến vào ngọn núi."},{"chuong":1676,"tieuDe":"Ngươi Có Dám Đường Đường Đánh Một Trận","tomTat":"Vương Lâm dừng chân trò chuyện với Tam phi, biết tên thật nàng là Đường San, thuộc Thiên Môn Đạo ở đại lục Tiên Cương. Vân Dật Phong cưỡi đài khổng lồ bao phủ cầu vồng đuổi tới, thách đấu đường đường chính chính với điều kiện không dùng âm mưu và cây cung Lý Quảng, đưa thệ huyết cam kết nếu thua sẽ nghe lệnh. Vương Lâm dùng quyền Đạo Cổ phá trường đao, rồi triệu hai cánh tay Diệp Mịch thi triển Tê Thiên Thuật đại thành xé hư không, phá tan hoàn toàn Bát Đao Trảm Thần Hồn của Vân Dật Phong. Vân Dật Phong thừa nhận thua, thệ huyết hoá lời thề ràng buộc, từ nay nghe lệnh Vương Lâm trong vùng trung tâm động phủ. Chưởng Tôn đạp không tới, Vương Lâm phóng huyết kiếm đẩy lùi hắn một bước, đồng thời sai Vân Dật Phong thi triển lại Bát Đao Trảm Thần Hồn tấn công. Đường San thi triển Thất Diện Kim Môn phòng hộ lên cả Vân Dật Phong và Vương Lâm, khiến Vương Lâm cả đời lần đầu chứng kiến thần thông phòng hộ có thể dùng cho người khác."},{"chuong":1677,"tieuDe":"Huyền La Xuất Thủ","tomTat":"Chưởng Tôn xuất hiện tại vùng đất cổ mộ, phán đoán Vương Lâm đã cạn sức sau ba lần giương cung nên quyết giết đoạt hồn thứ ba. Vân Dật Phong thi triển Bát Đao Trảm Thần Hồn và Đường San dùng chín phi kiếm phối hợp tấn công nhưng đều bị Chưởng Tôn đánh bại, cả hai phun máu bị thương. Vương Lâm thi triển Tê Thiên Thuật đối đầu Chưởng diệt tam đạo ba tầng của Chưởng Tôn — phá hai tầng đầu nhưng bị kim ấn tầng ba vượt qua. Vương Lâm không hoảng loạn, tỉnh táo lùi ba bước tới ngay sau lưng Huyền La rồi khoanh chân ngồi xuống, ép Huyền La ra tay. Huyền La cười tùy ý chỉ tay dừng kim ấn giữa không trung rồi biến nó từ thần thông hư ảo thành pháp bảo thực chất lơ lửng trước Vương Lâm. Chưởng Tôn kinh hãi tột cùng, nhận ra đây là năng lực chỉ cửu đại thiên tôn Tiên Cương Cửu Dương mới có, gọi Huyền La là ca ca của chủ nhân. Vân Dật Phong cũng nhận ra thân phận Huyền La, hoảng sợ vội cúi đầu — biểu cảm bị Vương Lâm nhìn thấy rõ ràng."},{"chuong":1678,"tieuDe":"Con Thú Cùng Đường","tomTat":"Vương Lâm nhận chủ kim ấn vô chủ do Huyền La sáng tạo từ hư ảo, nuốt vào nguyên thần tế luyện, kim ấn phong ấn Diệt Thần Đạo Thuật và chứa cửu dương lực. Chưởng Tôn tâm thần sụp đổ vì sự hiện diện của Huyền La, nghi ca ca của chủ nhân ẩn mình gần đó, bỏ ý định giết Vương Lâm điên cuồng bỏ chạy. Thác Sâm xuất hiện giao chiến rồi biến đổi — khí chất bá đạo tiêu tan, Đồ Ti thức tỉnh, trầm ổn tỉnh táo, triệu trường mâu khổng lồ. Vương Lâm lần đầu tiên hoàn toàn bành trướng thân thể Cổ Thần lên mấy vạn trượng, cùng Thác Sâm, Vân Dật Phong, Đường San bốn người vây đánh Chưởng Tôn. Vân Dật Phong hóa ác hầu tím nhập thể Chưởng Tôn theo thất khiếu, Đường San thất môn hợp nhất hóa cự long vàng nuốt lấy, Chưởng Tôn lần đầu phun máu tại đây, cảm nhận khí tức Lam Mộng Đạo Tôn đang lao tới. Vương Lâm phóng Cổ Tức Diệp phong kín đường lui, thi triển Tê Thiên Thuật, dùng Định Thân Thuật chặn nguyên thần huyết của Chưởng Tôn rồi phóng huyết kiếm xuyên vai hắn. Chưởng Tôn trong thế cùng đường thi triển đạo thuật Tình Trung Lao Nguyệt — lấy đất làm giếng phản chiếu trời, mò ra ảo ảnh giết hồn."},{"chuong":1679,"tieuDe":"Hồn Chưởng Tôn","tomTat":"Chưởng Tôn thi triển Tĩnh Trung Lao Nguyệt biến mặt đất tầng hai cổ mộ thành nước giếng phản chiếu thân ảnh bốn đối thủ. Vương Lâm nhận định đây là thời cơ tốt nhất và cảm nhận Lam Mộng Đạo Tôn đang tới. Lam Mộng xuất hiện từ đám mây lam, dùng tu vi cả đời phối hợp Vân Dật Phong, Đường San, Thác Sâm dung hợp lam quang tạo bốn ký hiệu phong ấn toàn thân Chưởng Tôn trong ba nhịp thở. Trong thời gian phong ấn, Vương Lâm dùng Mộng Đạo (mặt quỷ huyễn cảnh) điểm mi tâm Chưởng Tôn dung hợp hồn, rồi tế hồn cho Dĩ Ti, nuốt mất nửa hồn Chưởng Tôn. Chưởng Tôn mất nửa hồn, thần trí mơ hồ, lao tới định giết Vương Lâm nhưng Dĩ Ti hiện thân lần đầu tiên từ ngọn núi hắc khí, đánh bại Chưởng Tôn trong sương đen và ném hắn ra bất tỉnh. Dĩ Ti lộ nguyên hình — con quỷ tím đen bị xích, khí chết chóc kinh thiên — khiến tất cả kinh hãi, Huyền La nhận ra đó là khôi linh chuyển biến hai lần. Vương Lâm nhận xét Dĩ Ti chưa đạt đỉnh Không Kiếp Sơ Kỳ như ký ức Thất Thải Tiên Tôn, cần tế hồn thêm để khống chế. Cuối cùng Vương Lâm thu Chưởng Tôn vào không gian trữ vật, tuyên bố để người điên năm đó thức tỉnh rồi quyết định sống chết."},{"chuong":1680,"tieuDe":"Cổ Mộ Truyền Thừa","tomTat":"Vương Lâm sau khi lấy nửa hồn Chưởng Tôn, thầm cảm khái cho kẻ một đời kiêu hùng nhưng rơi vào luân hồi nhân quả — năm xưa vây giết Phong Tôn đến diệt vong, nay bản thân bị trả giá tương tự. Vương Lâm cảm tạ đồng minh và kết thúc nhân quả với Lam Mộng Đạo Tôn, Đường San, Vân Dật Phong. Ngọn núi Ác quỷ Dĩ Ti sụp đổ lộ ra hố sâu dẫn tới tầng cuối vùng đất cổ mộ. Chiến lão quỷ đuổi tới, thân phát ánh sáng bảy màu do đã cắn nuốt đạo nhân bảy màu, tu vi gần đạt mức Thất Thải Tiên Tôn năm xưa. Lam Mộng Đạo Tôn, Đồ Ti, Vân Dật Phong và Đường San tình nguyện ở lại hợp lực chặn Chiến lão quỷ. Vương Lâm lao xuống tầng cuối — nơi chỉ có trái tim khổng lồ trăm trượng của Diệp Mịch, tiếng tim đập cộng hưởng khiến mạch máu căng phồng, ho ra máu. Vương Lâm ngồi khoanh chân trên trái tim, dùng thần niệm thuyết phục Diệp Mịch, hứa hoàn thành di nguyện, chiếu cố thân nhân ở Tiên Cương đại lục và tìm mắt trái về. Trái tim chấp nhận đập cùng nhịp, Đạo Cổ khí tức mênh mông tràn vào cơ thể Vương Lâm, tám tinh điểm trên mi tâm xoay tròn, xuất hiện dấu hiệu hình thành tinh điểm thứ chín."},{"chuong":1681,"tieuDe":"Quần Chiến Chiến Lão Quỷ","tomTat":"Tại tầng cuối cùng vùng đất cổ mộ, Vương Lâm hấp thu khí tức Đạo cổ từ trái tim Diệp Mịch, tinh điểm trên mi tâm có dấu hiệu hình thành tinh điểm thứ chín. Hắn minh ngộ nguyên lý dùng nhịp tim dẫn động nhịp tim đối phương và tính toán sáng tạo thần thông mới kết hợp lôi bổn nguyên, Mộng Đạo và hư hỏa. Tại tầng thứ hai, ác chiến bùng nổ — Đường San bị trọng thương, Vân Dật Phong suýt chết, Thác Sâm bị phong ấn hoàn toàn, Huyền Vũ và Chu Tước chiến tướng giao chiến ngang tay với hai tu sĩ Ngũ Hành tinh. Trận chính diễn ra giữa Chiến lão quỷ với Lam Mộng Đạo Tôn và lão già họ Mã. Lam Mộng phun máu triệu cổ cầm chí bảo phong ấn nhiều năm trong máu — đòn sát thủ cuối cùng, lai lịch thần bí, là nguyên nhân Chưởng Tôn kiêng kỵ hắn. Lão già họ Mã thi triển Ngũ hành kim tiên và Ngũ hành thổ tiên, triệu hai bàn tay khổng lồ đánh Chiến lão quỷ. Bị dồn ép, Chiến lão quỷ vỗ mi tâm tách hồn phách Thất Thải Tiên Tôn ra khỏi thân chống cự. Cuối chương, tiếng tim đập và khí tức Đạo cổ của Vương Lâm tràn ra khỏi tầng cuối cùng, lan tới chiến trường."},{"chuong":1682,"tieuDe":"Tâm Động Lôi Âm","tomTat":"Hồn phách Thất Thải Tiên Tôn trong thân Chiến lão quỷ tung song chưởng đánh sụp thần thông lão già họ Mã và phong ấn cổ cầm Lam Mộng Đạo Tôn, khiến cả hai trọng thương. Chiến lão quỷ phân ly hồn phách, khôi phục bản tính bá đạo, dùng Chiến tự thiếp đánh trọng thương hai nam tử Ngũ Hành tinh, rồi sai Huyền Vũ và Chu Tước chiến tướng vào tầng cuối giết Vương Lâm. Đường San và Thác Sâm cố ngăn cản nhưng chậm hơn. Huyền Vũ vừa tới cửa vào tầng cuối thì bị tiếng tim đập ầm ầm dẫn động tâm thần, trái tim đau đớn, rồi bị ác quỷ Dĩ Ti lao ra đánh bay. Dĩ Ti bám lên Chu Tước chiến tướng ôm cổ hút máu, đạp hắn nện xuống đất. Vương Lâm xuất hiện với hình dạng đại biến sau truyền thừa Diệp Mịch: bạch y đầy máu, tóc bạc, da lộ phù văn, đặc biệt hai mắt biến thành ngân mục (mắt bạc) — đệ nhất tượng trong cửu khúc tam tượng nhờ hồn huyết cổ Tổ. Lão già họ Mã và Huyền La Đại Thiên Tôn kinh ngạc nhận ra ngân mục. Vương Lâm chủ động nhận trận chiến, phát động thần thông Tâm Động Lôi Âm — tiếng tim đập khuếch tán thành tiếng duy nhất trong thiên địa, khiến Chiến lão quỷ (đã dung hợp lại Thất Thải Tiên Tôn) trái tim đau đớn không thể khống chế."},{"chuong":1683,"tieuDe":"Đạo Cổ Vô Tiên","tomTat":"Vương Lâm chuyển hóa toàn bộ tu vi thành khí tức Đạo cổ, mở lời tuyên chiến với Chiến lão quỷ, coi trận hôm nay là tiếp nối số mệnh của Diệp Mịch năm xưa. Hắn dùng Tâm Động Lôi Âm khống chế nhịp tim Chiến lão quỷ suýt khiến tim tan vỡ, rồi ngưng tụ chín tinh điểm Cổ Thần cùng mười bảy tinh điểm yêu ma vào quyền Đạo cổ đối đầu bảy chữ Chiến — cả hai bên chịu thương. Sau đó Vương Lâm lần lượt thi triển ba thuật: Thần Chấn binh tu liệt vị xoay thiên địa, Yêu Thuật phong hỏa thành sơn tạo lốc phong hỏa, Ma Đạo sinh tử nghịch động biến thiên địa thành biển chết. Cuối cùng hắn dung hợp tam tộc thành tuyệt chiêu Đạo Cổ Vô Tiên, triệu ra hư ảnh đầu lâu Cổ Tổ khổng lồ cao ngang thiên địa, khí tức phun ra hóa đá toàn bộ cổ mộ từ tầng một đến tầng cuối cùng Chiến lão quỷ và hai hồn Thất Thải Tiên Tôn. Huyền La nhìn thấy hư ảnh sùng kính gọi Cổ tổ. Tuy nhiên Chiến lão quỷ phá hóa đá thoát thân, hai hồn Thất Thải bị cưỡng ép dung nhập trở lại thân hắn khiến hắn hoảng sợ bỏ chạy. Đệ tứ hoa nở tung, cổ mộ sụp đổ hoàn toàn. Vương Lâm kiệt sức khạc máu, tự nhận vẫn không phải đối thủ do thiếu mắt trái khiến Cổ Yêu chưa cửu tinh, quyết định đi tìm đệ ngũ hoa để mượn sức mạnh Tiên Cương phong ấn Chiến lão quỷ."},{"chuong":1684,"tieuDe":"Vũ Lạc Đông Lâm Thanh Yên Khởi","tomTat":"Ở trung tâm động phủ, Vương Lâm tiến vào đệ ngũ hoa của Ngũ Hoa Bát Môn trận — thử thách cuối cùng. Hồn thứ ba (ký ức cả đời Thất Thải Tiên Tôn) biến đệ ngũ hoa thành thế giới ký ức bảy màu, Vương Lâm hóa thành hình dạng Tô Đạo (tên thật Thất Thải Tiên Tôn thời trẻ), mặc đạo bào xanh có lực phòng hộ cấp vấn Đỉnh. Hắn nhận ra hình dạng mình giống pho tượng bảy màu lấy từ Tham Lang và cảm giác chưa hoàn toàn dung hợp với hồn thứ ba ở mức sâu, đã ở đây hơn hai tháng mà chưa tìm được chân môn. Cảnh tượng đại lục Tiên Cương lần đầu hiện ra: chín mặt trời, tiên khí sung mãn, sinh linh tráng kiện, cỏ cây có linh hồn, mãnh thú hóa người. Một thanh niên đồng môn phụng mệnh đại sư huynh tới bắt Tô Đạo về chịu phạt, Vương Lâm dùng ánh mắt uy áp rồi túm cổ nhấc lên cảnh cáo, không để lịch sử bắt nạt lặp lại. Qua ký ức, lộ ra Thất Thải Tiên Tôn thời trẻ thiên tư tuyệt hảo nhưng mềm yếu, bị đồng môn đố kỵ bài xích, mười năm sau mới được sư tổ phát hiện. Vương Lâm dẫn thanh niên lên đỉnh núi tới đại điện rộng trăm trượng, nơi gần trăm tu sĩ tụ tập cung nghênh sư tôn xuất quan, trời đổ mưa lớn ngay khi hắn bước vào sân."},{"chuong":1685,"tieuDe":"Vân Đạo Càn Khôn Nghịch!","tomTat":"Trong thế giới ký ức Thất Thải Tiên Tôn, sư tôn Liên Đạo Phi xuất quan từ dòng xoáy khói xanh lư hương chín cây, triệu Tô Đạo và đại sư huynh Chu Lập vào đại điện để truyền thụ Vân Đạo Thiên Thuật — một trong tam đại tối cường thần thông Đông Lâm Tông, mỗi thế hệ chỉ truyền một người. Phương pháp chọn lựa là vận chuyển vân khí, ai nhanh và mây mù nồng đậm hơn sẽ thắng. Vương Lâm nhận ra nếu thuận theo ký ức gốc, dung hợp hoàn toàn hồn thứ ba thì Tạ Thanh sẽ tan thành mây khói, hắn không chấp nhận. Khi Chu Lập dùng ánh mắt uy hiếp, Vương Lâm bùng phát sát khí chấn nhiếp đối phương, chỉ tám nhịp thở vận chuyển xong vân khí, mây mù hóa rồng nuốt sạch sương mù Chu Lập khiến hắn phun máu. Kết quả đảo ngược hoàn toàn: Tô Đạo được truyền Vân Đạo Thiên Thuật, Chu Lập nhận Thất Thải Tiên Thuật. Thế giới ký ức vặn vẹo, tám luồng khí bát môn bốc lên, Vương Lâm ngộ ra phương pháp duy nhất phá bát môn: thay đổi ký ức tạo mâu thuẫn để cảm nhận vị trí bát môn, mâu thuẫn càng lớn cảm nhận càng rõ."},{"chuong":1686,"tieuDe":"Thôn Vân Thổ Vụ Nhất Môn Hiện","tomTat":"Vương Lâm ngồi bên bờ sông trong thế giới đệ ngũ hoa, hồi tưởng ký ức hồn thứ ba về cuộc đời Tô Đạo tại Đông Lâm Tông — từ thất bại cuộc thi, bị khu trừ cho tới sáng lập Thất Đạo Tông và giết Chu Lập ngày thành đạo. Vương Lâm bắt đầu tu luyện Vân Đạo Thiên Thuật, hấp thu vân khí từ sông, cây cỏ rồi bay lên bầu trời hóa đám mây hấp thu mây đen trên bình nguyên suốt hơn hai tháng. Mây mù cuối cùng hóa bảy con vân long chui vào thất khiếu, đồng tử biến thành mây mù, đạt tầng thứ chín gần đại viên mãn. Thu hoạch lớn nhất là nhờ không ngừng kích thích ký ức hồn thứ ba trong quá trình tu luyện, Vương Lâm tìm ra vị trí đệ nhất quan trong bát môn. Hắn lao tới vùng rừng rậm, phát hiện đệ nhất quan không phải cây đại thụ mà chính là con mãng xà trăm trượng quấn quanh — trên lưng mãng xà hiện cánh cửa biến ảo. Vương Lâm nắm cổ mãng xà, từng bước tiến về phía cánh cửa."},{"chuong":1687,"tieuDe":"Càn Khôn Đệ Nhất Quan","tomTat":"Vương Lâm rời nơi tìm bát môn sau khi xác nhận mãng xà là một trong bát môn nhưng không phải cửa thực, nhận định Vân Đạo Thiên Thuật dù viên mãn cũng chưa đủ biến đổi ký ức hồn thứ ba. Hắn quyết định chờ cuộc thi đấu đệ tử cấp thấp sáu năm một lần của Đông Lâm Tông — kỷ niệm khắc sâu của Thất Thải Tiên Tôn — để nghịch chuyển ký ức tìm cửa thật. Ba tháng sau, sư tôn Tô Đạo xuất quan, chọn Vương Lâm (giả Tô Đạo), Chu Lập và Tần Mai dự thi. Tại quảng trường khai mạc, Vương Lâm bình tĩnh trước uy áp mấy trăm cường giả, thu hút hơn mười ánh mắt chú ý, hoàn toàn đảo ngược kịch bản ký ức cũ khi Tô Đạo chỉ run rẩy cúi đầu còn Chu Lập tỏa sáng. Chu Lập đố kị oán hận vì bị lướt qua, Tần Mai ngạc nhiên trước khí chất thay đổi của Tô Đạo. Hơn ngàn đệ tử tiến vào khe Đông Lâm — vùng đất đen kịt mô phỏng Tiên Cương đại lục — bắt đầu đệ nhất quan với quy tắc thu 30 lệnh bài trong ba ngày. Vương Lâm xuất hiện tại bình nguyên cỏ dại, nhớ lại năm xưa Tô Đạo bị Chu Lập ngược đãi tàn nhẫn chính tại nơi này, tự nhủ sẽ thay đổi tất cả."},{"chuong":1688,"tieuDe":"Tô Đạo Nhất Biến Thiên Địa Băng","tomTat":"Vương Lâm đóng vai Tô Đạo trong thế giới đệ ngũ hoa (ký ức hồn thứ ba Thất Thải), tham gia tỷ thí cửa thứ nhất Đông Lâm Tông nhằm kích thích hồn thứ ba hỗn loạn để khí tức bát môn hiển lộ. Hắn lần lượt cướp lệnh bài ngọc bội của các đệ tử, đánh bại Côn Bằng — thiên tài sở trường tốc độ đứng thứ ba cửa thứ nhất — khiến hắn hoảng sợ vứt ngọc bội bỏ chạy. Tiếp đó Vương Lâm phá sập núi giết chết Chu Lập — kẻ hận Tô Đạo vì tranh giành quyền học Vân Đạo Thiên Thuật — cái chết này kích thích mạnh ký ức hồn thứ ba, giúp Vương Lâm cảm nhận vị trí tam môn trong bát môn. Sau khi quét sạch toàn bộ ngọc bội, Vương Lâm xé trời bước ra ngoài tuyên bố đứng đầu tỷ thí, khiến thế giới đệ ngũ hoa sụp đổ hoàn toàn và khí tức bát môn hiển lộ toàn bộ như cột khí bốc lên chín tầng mây. Thứ duy nhất không sụp đổ trên mặt đất là Đông Lâm Trì ở hậu sơn Đông Lâm Tông."},{"chuong":1689,"tieuDe":"Đông Lâm Trì Nội Ngư Long Biến!","tomTat":"Trong thế giới ký ức đệ ngũ hoa, Đông Lâm Trì là tâm nguyện cả đời chưa hoàn thành của Thất Thải Tiên Tôn (Tô Đạo) — hắn từng được sư tổ Đông Lâm Tông bồi dưỡng nhưng bị khu trừ ngay khi đạt tư cách vào ao. Vương Lâm kêu gọi Tô Đạo giúp tìm cánh cửa thật trong bát môn, đổi lại sẽ hoàn thành tâm nguyện vào Đông Lâm Trì. Vương Lâm lao vào Đông Lâm Trì, nước ao chứa lực lượng bổn nguyên khổng lồ khiến bảy đạo bổn nguyên (hỏa, lôi, sinh tử, nhân quả, chân giả, sát lục, cấm chế) đạt viên mãn, lần lượt ngưng tụ thành bảy bổn nguyên chân thân. Thủy bổn nguyên (đạo thứ tám) hấp thu toàn bộ nước ao còn lại mà đại thành, hình thành chân thân thứ tám, tu vi đột phá lên Không Linh đỉnh — tuy nhiên tất cả là hư ảo trong ký ức. Đông Lâm Trì cạn nước sụp đổ, thế giới ký ức bị hủy diệt, cánh cửa thật trong bát môn lộ khí tức mãnh liệt. Chiến lão quỷ lao tới nhưng không đuổi kịp Vương Lâm nhờ Vân Đạo Thiên Thuật cùng tám bổn nguyên chân thân. Vương Lâm tới trước đại môn động phủ giới, dồn toàn bộ Đạo Cổ lực đánh ra một chưởng mở khe hở, trở thành người đầu tiên mở được đại môn sau phong bế — khí tức thần chính Tiên Cương đại lục tràn vào."},{"chuong":1690,"tieuDe":"Phần Sí Dục Tầm Tiên Cương Mộng","tomTat":"Đại môn động phủ giới mở ra khe hở, khí tức Tiên Cương đại lục tràn vào. Chiến lão quỷ bước ra từ thiên địa sụp đổ, uy hiếp Vương Lâm giao hồn thứ ba và đe giết người liên quan. Vương Lâm kích hoạt hai đạo phong ấn do Tạ Thanh để lại, chờ dung hợp khí tức Tiên Cương để hoạt hóa. Dùng tám bổn nguyên chân thân đánh chưởng, lần đầu tiên đẩy lui Chiến lão quỷ cùng lưỡng hồn Thất Thải Tiên Tôn, rồi nương lực phản chấn đập mở rộng đại môn tới gần ba phần. Hai đạo phong ấn phóng ra như số mệnh, phong ấn lưỡng hồn Thất Thải thành hai quả cầu ánh sáng cỡ nắm tay, cắt đứt liên hệ với Chiến lão quỷ. Chiến lão quỷ trở lại minh mẫn, thú nhận giấc mộng cả đời là mở đại môn và năm đó độ Huyền Kiếp thất bại rồi bị hồn phách Thất Thải dung hợp. Cảm ơn Vương Lâm rồi thân thể tiêu tán, nửa còn lại hóa cầu vồng lao vào đại môn, tan thành mây khói bên ngoài mà chết."},{"chuong":1691,"tieuDe":"Ôm Quyền Nhất Bái Trần Thổ Tán","tomTat":"Đại đỉnh trong động phủ giới bị hắc khí bao phủ và vỡ ra, lộ kim môn hoàng kim cao chọc trời nối tới Tiên Cương đại lục. Hư ảnh những người còn sống hiện ra bên ngoài kim môn: Thác Sâm, Lam Mộng đạo tôn, Đường San, đoàn Ngũ Hành Tinh và Vương Lâm. Tám bổn nguyên chân thân của Vương Lâm tiêu tán khi trở lại thân xác, Thủy bổn nguyên chỉ còn chút thành tựu, bảy bổn nguyên ẩn trong thân trở về trạng thái trước biến hóa Đông Lâm Trì. Vương Lâm tuyên bố xóa bỏ ân oán cũ, ôm quyền tiễn biệt từng người: Lão già họ Mã mời hắn tới Quy Nhất Tông ở Tiên Tộc, Vân Dật Phong hẹn phân thắng bại ở Tiên Cương, Bạch Hổ chiến tướng được phóng thích. Ba chiến tướng Huyền Vũ, Chu Tước, Bạch Hổ tạ lỗi rồi bay vào kim môn. Đường San rơi lệ từ biệt, quay đầu hỏi có thể gặp lại không, Vương Lâm im lặng, nàng biến mất trong kim quang. Sau khi tất cả rời đi, Vương Lâm ôm quyền vái về phía hư vô, gọi đích danh Huyền La Đại Thiên Tôn — kẻ đã bám theo hắn từ Ngũ Hành Tinh tới Tiên Giới — buộc một thân ảnh mơ hồ lộ diện, kinh ngạc hỏi sao Vương Lâm biết tên mình."},{"chuong":1692,"tieuDe":"Ta Và Thê Tử Quyết Không Rời Nhau","tomTat":"Huyền La Đại Thiên Tôn chính thức hiện thân trước Vương Lâm, Lam Mộng đạo tôn và Thác Sâm, thần thức không thể cảm nhận sự tồn tại của hắn. Huyền La tự suy đoán đúng cách Vương Lâm phát hiện thân phận mình thông qua thần thức tu sĩ Ngũ Hành Tinh và khí tức Mục Ngư. Huyền La xác nhận thân phận: một trong Cửu Dương, Đại Thiên Tôn của Đạo Cổ nhất mạch tại Tiên Cương đại lục, và mời Vương Lâm làm đệ tử duy nhất. Huyền La giải thích quy tắc Tiên Cương: sinh linh không có huyết mạch sẽ bị hồn phi phách tán, bác bỏ tiếp dẫn giả là lừa gạt. Huyền La tiết lộ hồn Uyển Nhi không hoàn chỉnh, một phần đã biến mất không dấu vết. Vương Lâm chảy huyết lệ tuyệt vọng, tuyên bố thà ở lại động phủ giới vĩnh viễn với Uyển Nhi chứ không một mình tới Tiên Cương. Huyền La đề xuất Thiên Dương luân hồi chuyển thế thuật cho bằng hữu chuyển thế đầu thai, riêng Uyển Nhi cho năm phần mười cơ hội mang trực tiếp, thất bại thì cả hai tử vong, Huyền La phải trả giá rất lớn. Vương Lâm ghi nhận mang ân Huyền La, giống như năm xưa mang ân Độn Thiên."},{"chuong":1693,"tieuDe":"Vô Hối Hệt Năm Xưa","tomTat":"Vương Lâm đứng ngoài kim môn động phủ giới, tiếp nhận lời Huyền La giải thích cơ chế chuyển thế đầu thai: người rời đi không có huyết mạch Tiên Cương sẽ mất vài năm đến ngàn năm, xuất hiện ở góc bất kỳ trên Tiên Cương đại lục với ký ức bị che mờ. Vương Lâm tuyên bố nếu không thể đồng sinh với Lý Mộ Uyển thì xin cộng tử, hai chữ “vô hối” vang khắp tinh không, thể hiện đạo tâm hơn hai ngàn năm tu đạo. Huyền La đánh giá Vương Lâm có nhân-nghĩa-tình, âm thầm quyết định hắn phù hợp yêu cầu bảo vệ Đạo Cổ nhất mạch tới vĩnh hằng, hẹn một tháng sau làm phép. Thác Sâm do dự về chuyển thế đầu thai, Lam Mộng đạo tôn nghe hai tiếng “vô hối” ánh mắt ảm đạm nhìn về Tiên Giới trầm mặc. Vương Lâm bay tới Đông Lâm Tinh đã sụp đổ, dùng lực Tê Thiên xé khe không gian, phun tu vi Đạo Cổ phá tầng băng trong thế giới đóng băng đệ nhị hoa. Vân Na chủ động tách hồn phách, để lại thân thể Cổ Thần nuôi dưỡng nơi này báo ân chủ nhân sáng tạo, hồn phách được thu vào Không Gian trữ vật. Vương Lâm vượt La Thiên hướng về Vân Hải tinh vực đón Phàn San Lộ, đồng thời nhớ ra lời hứa cho một hồn phách bí ẩn trong trữ vật tu vi và thân thể."},{"chuong":1694,"tieuDe":"Tâm Trạng Lúc Biệt Ly","tomTat":"Vương Lâm dành mười ngày giải quyết việc tồn đọng trong động phủ giới: giúp Phàn San Lộ mở đại môn rời đi về quê hương Tiên Cương, thu chiếc thuyền khổng lồ (buồm mặt quỷ), tìm tu chân tinh và nhập hồn phách vào thân thể mới tạo Nguyên Thần. Sau đó trở lại Tiên Giới, tản thần niệm thông báo: nửa tháng nữa sẽ rời đi, ai muốn theo thì tới tìm hắn nhưng phải chấp nhận chuyển thế đầu thai. Tư Đồ Nam tới gặp hắn ngày thứ hai, hai người chia bầu rượu, Tư Đồ Nam quyết chuyển thế tới Tiên Cương đại lục náo loạn một phen, dặn Vương Lâm đừng quên đi tìm. Thanh Thủy và Hồng Điệp phụ tử cùng tới, hy vọng trên Tiên Cương đại lục tìm cách đưa Hàm Yên trở lại để cả nhà đoàn tụ. Thập Tam quyết theo sư phụ dù sống chết. Lý Thiến Mai mặc bạch y tới ngày thứ chín, phân vân giữa ở lại với phụ thân hay đi chờ Vương Lâm, cuối cùng khi Vương Lâm nắm tay hứa sẽ tìm nàng và giải khai ký ức bị che phủ, nàng rơi lệ kiên định sẽ đi. Chưa tới hai mươi người chọn rời đi; Hồng Sam Tử, Chu Như, Thân Công Hổ chọn đi; Nam Vân Tử, Chiến Không Liệt, Viêm Lôi Tử chọn ở lại. Thanh Lâm, Thanh Sương, Chu Dật tới trong hoàng hôn — Chu Dật đau đớn nhìn khuôn mặt quen thuộc của Thanh Sương nhưng là người khác. Ngày cuối cùng, Mộc Băng Mi mặc bạch y cầm ô đi tới trong mưa, trang phục và ánh mắt nàng khiến Vương Lâm nhớ tới Liễu Mi, không thể quên nổi."},{"chuong":1695,"tieuDe":"Long Hoàng Nhất Hiện Tiên Cương Khai","tomTat":"Mộc Băng Mi cầm ô đứng trong mưa tiễn biệt Vương Lâm, hai người hẹn ước nếu còn sống sẽ gặp lại. Vương Lâm ngưng tụ bảy đạo bổn nguyên thành thanh kiếm dung hợp khí tức Đạo Cổ tặng cho nàng, sau đó xoay người rời đi cùng Lý Thiến Mai. Trên đường, Vương Lâm trầm mặc suy nghĩ về các bí ẩn còn lại của động phủ giới — Chu Tước đời đầu ở Điên Lạc, cây kim la bàn Thiên Nghịch, Xích Hồn Tử đã được thả, người thần bí phong ấn ở Tiên Giới — cố ý lưu lại làm chấp niệm để vĩnh viễn không quên quê hương. Hắn mang mấy chục người tới đại môn động phủ trong La Thiên tinh vực gặp Huyền La Đại Thiên Tôn, cố ý giữ số lượng ít để giảm gánh nặng cho Huyền La. Huyền La bắt quyết triệu hoán Long Hoàng thiên nhất — một con rồng khổng lồ sừng hình vương miện, thân mấy vạn trượng, có lực Không Kiếp trung kỳ, thu nhỏ thành cây long tiên huyết sắc dài trăm trượng. Huyền La tuyên bố sẽ dùng cây roi này phá quy tắc Tiên Cương đại lục, mở lỗ hổng thiên địa cho mọi người chuyển thế đầu thai. Vương Lâm kinh hãi trước uy lực cây tiên, cảm thấy bản thân cũng không thể chịu nổi."},{"chuong":1696,"tieuDe":"Tứ Linh Mở Đường Mộng Đạo","tomTat":"Huyền La lần lượt triệu hồi bốn đại linh hoàn thành con đường chuyển thế đầu thai thông tới Tiên Cương: Hoàng Long Tiên xé sương mù mở đường mình rồng, Sơn Yêu phủ băng bảo vệ hồn phách, Kiếm Tiên hộ tống dẫn đường, Phong Ma phong ấn ký ức và che giấu thân phận kiếp trước. Huyền La trao mặt trời Đại Thiên Tôn lực cho Vương Lâm để khuếch đại Mộng Đạo Thuật, Vương Lâm thi triển phong ấn ký ức mọi người vào mộng và tạo ký hiệu liên kết trên mi tâm để tương lai tìm lại. Thanh Lâm hào sảng ôm quyền chào rồi bước vào sương mù đầu tiên, Thanh Sương quay đầu nói lời ẩn ý với Chu Dật trước khi biến mất. Vương Lâm chuyển một phần ấn ký Thanh Sương lên trán Chu Dật tạo liên hệ hai người sau chuyển thế, xóa ký ức đau khổ cho hắn rồi để hắn ra đi. Thanh Thủy gọi Vương Lâm là sư đệ, nhờ chiếu cố con gái rồi bước vào chuyển thế. Hồng Điệp mắt đỏ khóc, muốn nói nhưng không mở miệng, nước mắt hóa cầu vồng đỏ như con bướm biến mất vào đại môn động phủ."},{"chuong":1697,"tieuDe":"Hôm Nay Vương Mỗ Tới Nơi Này Đưa Ngươi Đi Đầu Thai!","tomTat":"Đám người bên cạnh Vương Lâm lần lượt từ biệt rồi bước vào đại môn động phủ chuyển thế đầu thai tới Tiên Cương đại lục. Thập Tam quỳ bái thề không quên ân sư đồ, Tư Đồ Nam sảng khoái ném bầu rượu cho Vương Lâm tuyên bố kiếp sau đầu thai thành vương gia, Lý Thiến Mai là người cuối cùng, thề sẽ chờ Vương Lâm trong luân hồi hết lần này tới lần khác. Sau khi mọi người rời đi, Vương Lâm xin Huyền La cho thêm chỗ chuyển thế, quyết định đưa tam tôn Thái Cổ còn lại đi đầu thai thay vì giết để giải quyết mối họa cho động phủ giới. Tu vi Vương Lâm sau ngũ hoa bát môn đạt đỉnh Không Linh, chiến lực ngang Không Huyền Hậu Kỳ, truyền thừa Đạo Cổ gần viên mãn. Vương Lâm vượt trận pháp giới nội–giới ngoại vào Thái Cổ Tinh Thần, tìm tới tu chân tinh hình trăng lưỡi liềm phía đông nơi Cửu Thiên ma tôn ẩn náu trị thương. Dùng Tê Thiên Thuật hai tay xé đôi toàn bộ tu chân tinh, phá tan phòng ngự, phong ấn Cửu Thiên ma tôn thu vào Không Gian trữ vật chỉ trong vài nhịp thở. Tiếp tục tìm tới thủy tinh phía tây nơi Diệu Âm đạo tôn đang trị thương dưới đáy biển, xuất hiện trên hải dương tuyên bố đưa Diệu Âm đi đầu thai."},{"chuong":1698,"tieuDe":"Gặp Nhau Ở Tiên Cương Đại Lục","tomTat":"Vương Lâm lần lượt thu phục Diệu Âm đạo tôn đang ẩn dưới đáy biển vàng và Hư Thần thiên tôn đang bế quan trên đá vụn phía nam Thái Cổ Tinh Thần, phong ấn thu vào Không Gian trữ vật. Tiếp đó xông vào Thương Viên Tộc phong ấn lão tổ bước thứ ba mang đi, rồi quét sạch toàn bộ toàn năng bước thứ ba còn lại trong giới ngoại. Dùng hơn mười lá Cổ Tức Diệp phong ấn tinh không quanh tu chân tinh của tất cả bộ tộc, hạn chế tu sĩ suốt đời chỉ tới Toái Niết, khiến Thái Cổ Tinh Thần giới ngoại từ nay rất khó có bước thứ ba xuất hiện. Trở về La Thiên tinh vực, thả tám toàn năng bước thứ ba ra trước Huyền La, tuyên bố ân oán xóa sạch sau đầu thai, dùng cuồng phong cuốn tám người vào đám sương đen trong đại môn. Vương Lâm từ biệt Huyền La, hóa cầu vồng lao vào đại môn hướng tới Tiên Cương đại lục. Huyền La bước vào theo, đại môn bắt đầu đóng lại. Nửa canh giờ sau, ngay trước khi cổng khép hẳn, một đạo u quang bí ẩn từ sâu trong tinh không vội vàng bay tới chui vào cửa rồi biến mất."},{"chuong":1699,"tieuDe":"Một Tiếng Sư Tôn Bảo Vệ Đạo Cổ Nhất Mạch","tomTat":"Trên con đường mình rồng, Huyền La chỉ dẫn Vương Lâm rời vào hư vô để đối chọi pháp tắc Tiên Cương, bảo vệ đám người chuyển thế đầu thai an toàn tiến vào Tiên Cương đại lục. Huyền La đề nghị nhận Vương Lâm làm đệ tử, muốn truyền y bát Đạo Cổ nhất mạch và giúp hắn tiến vào Thái Cổ Thần Cảnh trở thành mặt trời thứ mười. Vương Lâm chính thức gọi Huyền La là sư tôn, thề đem tính mạng bảo vệ Đạo Cổ nhất mạch. Huyền La phun máu Cửu Dương hóa huyết long cuốn Vương Lâm lao vào lỗ hổng, hẹn mười năm chờ ở Tiên Cương. Trước khi rời, Vương Lâm thả toàn bộ sinh linh trong Không Gian trữ vật ra gửi sư tôn, ngoại trừ người điên. Đàn Văn Thú do Văn Thú Vương cầm đầu bất ngờ phát cuồng lao vào hư vô lột xác, đại bộ phận nổ tung tử vong, nhưng cuối cùng Văn Thú Vương tiến hóa thành công thân thể to bằng tu chân tinh, chín con Văn Thú vàng sống sót to vạn trượng. Huyền La kinh ngạc nhận ra chúng có thể là một trong chín loài thú cùng sinh với Cổ Tổ và Tiên Tổ, có khả năng dung hợp pháp tắc Tiên Cương."},{"chuong":1700,"tieuDe":"Hoàng Tông Nhất Niệm Họa Căn Hiện","tomTat":"Vương Lâm kích động sau khi Văn Thú dung hợp, cưỡi Văn Vương cùng chín Văn Thú hộ vệ chào biệt sư tôn Huyền La rồi lao vào hư vô hướng Tiên Cương đại lục. Huyền La phong kín lỗ hổng tầng băng, suy đoán Văn Thú có thể là hung thú truyền thuyết khi cổ tộc và Tiên Tộc sinh ra pháp tắc, nhận định Vương Lâm có khả năng trở thành Đại Thiên Tôn thứ 11 giúp Đạo Cổ nhất mạch vạn thế trường tồn; ngoài thân huyễn hóa mặt trời huyết sắc, dùng lực lượng một người chống pháp tắc Tiên Cương trên con đường mình rồng hộ tống từ xa. Hành trình xuyên hư vô vô biên — không ánh sáng, không linh khí, thi thể thiên tài trôi nổi khắp nơi; năm thứ hai huyết long tiêu biến, áp lực pháp tắc đè nặng, lực lượng bổn nguyên hao mòn không hồi phục; năm thứ tư chín Văn Thú không chịu nổi được thu vào trữ vật, chỉ Văn Vương duy trì tốc độ. Năm thứ năm Vương Lâm lấy Tị Thiên Quan chứa hồn phách Lý Mộ Uyển đặt sau lưng bảo vệ bằng toàn bộ lực lượng, nhớ về Mộc Băng Mi không còn hận nàng. Chuyển cảnh tới hoàng cung Đạo Cổ nhất mạch trên Tiên Cương đại lục — hoàng tôn mặc hoàng bào cầm quả cầu chứa hồn phách bí ẩn ngủ say, khinh thường Huyền La, tự nhận là người thủ hộ tộc. Theo lời quốc sư, hồn phách này có thể giúp hắn nắm cả Tiên Cương; hoàng tôn quyết định tìm nữ tử dung hợp với hồn phách, ra lệnh cho thuộc hạ Diệp Đạo thực hiện."},{"chuong":1701,"tieuDe":"Ý Chí Quật Cường!","tomTat":"Vương Lâm đã tiến vào vùng hư không ẩn chứa pháp tắc Tiên Cương được sáu năm, Tiên Cương đại lục bình yên, Đạo Cổ và Tiên Tộc không xô xát lớn, thiên tài Vân Dật Phong tỏa sáng, hoàng tôn tiên hoàng nhất mạch xuất quan sau mấy vạn năm khiến nửa Tiên Cương bị tiên khí bao phủ. Huyền La huyễn hóa xuất hiện tại Thất Đạo Tông ở Thiên Ngưu Châu, xác nhận mọi người khác đã chuyển thế đầu thai an toàn và nói còn không tới bốn năm cho hành trình của Vương Lâm. Bổn nguyên lực Vương Lâm gần khô kiệt, huyết long tiêu tán, chỉ còn dựa thân thể Đạo Cổ chống pháp tắc, suốt hành trình phải bảo vệ thê tử Lý Mộ Uyển phía sau. Năm thứ tám sắp không chịu nổi, Vương Lâm bùng phát Đạo Cổ lực giam cầm Văn Vương cưỡng ép chia tay, phóng chín Vụ thú đưa nó đi để một mình tiến bước. Văn Vương lần đầu tiên không muốn nghe lời, gào thét bi ai nhưng không tìm được chủ nhân, cuối cùng quyết tâm dung hợp khí tức Tiên Cương tiến hóa đỉnh phong để tìm lại Vương Lâm. Năm thứ chín, Vương Lâm thân thể mệt mỏi cực hạn nhưng ý chí nghịch thiên quật cường vẫn tồn tại, bước từng bước nặng nề như hơn hai ngàn năm trước tại Hằng Nhạc phái."},{"chuong":1702,"tieuDe":"Bạch Quang Kỳ Dị","tomTat":"Trên đỉnh Hắc Sơn của Thất Đạo Tông, Huyền La chờ Vương Lâm đã quá hạn ước định mười năm, nhưng hồng ấn chỉ đường trên mi tâm hoàn toàn tiêu tan khiến hắn bi thảm tin rằng đồ nhi đã chết. Trong tầng hư vô giữa động phủ và Tiên Cương đại lục, Vương Lâm mang theo Tị Thiên Quan tiến bước bằng ý chí bảo vệ Lý Mộ Uyển, gặp hài cốt lão già tỏa bạch quang thứ hai và hút sức mạnh kỳ dị lạnh lẽo để khôi phục bổn nguyên héo rũ cùng sức mạnh Đạo Cổ. Một năm sau không gặp thêm thi thể nào, tu vi cạn kiệt như đèn hết dầu, hắn hôn mê không còn khí tức nhưng vẫn dùng thân thể che chở chiếc quan tài đã tràn ngập vết nứt; Tị Thiên Quan mất phương hướng, trôi lạc trong hư vô suốt nhiều năm. Huyền La đợi đủ mười lăm năm thì hai mặt trời tiên khí kinh thiên động địa xuất hiện, buộc hắn dặn lại lời hẹn gặp ở Đạo Cổ nhất mạch rồi hóa huyết ảnh rời khỏi Thất Đạo Tông. Trên Tiên Cương đại lục, một vài người đã chuyển thế đầu thai thành hai đứa trẻ kỳ lạ ở tây châu và nam châu; nhiều người quên Vương Lâm nhưng Mộc Băng Mi, Đường San và Vân Dật Phong của Quy Nhất Tông vẫn nhớ. Huyền La trở về Đạo Cổ nhất mạch trong ảm đạm, còn Đạo Cổ hoàng tôn thấy vậy âm thầm cười lạnh. Trong hư vô, Văn Thú Vương dung hợp pháp tắc Tiên Cương, mười năm lột xác năm lần rồi hóa thành đám sương khói hung sát không thân thể, nuốt chín con văn thú đồng bạn dung hợp thành một thể và lao vào sâu hư vô đi tìm chủ nhân Vương Lâm."},{"chuong":1703,"tieuDe":"Phân Thân Mạnh Nhất!","tomTat":"Văn Thú — con thú khói của Vương Lâm — bất chấp nguy hiểm lột xác năm lần, cắn nuốt đồng bạn để tiến hóa, phân thành mười vạn phần tìm kiếm chủ nhân trong hư vô. Nó tìm được thi thể Vương Lâm tỏa bạch quang, tay phải bấu chặt quan tài suốt mấy chục năm không buông; mười vạn con tụ lại hóa thành Văn Thú Vương. Sau nhiều lần cố đánh thức chủ nhân thất bại, Văn Thú Vương cuốn thi thể và quan tài bay đi, dựa vào ký ức mơ hồ về pháp tắc Tiên Cương tìm được một đài cao hình cánh cung vạn trượng trôi dạt trong hư vô — nơi tổ tiên chín loài thú kỳ dị được sinh ra, có vách ngăn pháp tắc Tiên Cương mà ngay cả Huyền La cũng khó vào. Văn Thú Vương hút giọt máu tươi từ tim Vương Lâm, lấy thân bảo vệ lao vào vách ngăn, thân thể tiêu tan hơn phân nửa, đưa được một tia máu rơi lên đài. Đài hấp thụ giọt máu, chấn động hút bạch quang từ khắp hư vô, mềm ra hóa thành thân xác bằng đá khổng lồ; bên trong huyết khí dung hợp bạch quang ngưng tụ thành hư ảnh Vương Lâm — phân thân. Vương Lâm chậm rãi tỉnh dậy, sức mạnh Đạo Cổ hồi phục, bảy đạo bổn nguyên đạt tới đỉnh; hắn cảm nhận có một Vương Lâm khác cùng tồn tại, nhìn thấy thân xác đá có người giống mình, rơi vào hoang mang."},{"chuong":1704,"tieuDe":"Tiên Cương Rung Động!","tomTat":"Vương Lâm cảm ứng phân thân của mình trong xác đá, mơ hồ không rõ mình đang ở ngoài hay bên trong. Hắn dung hợp thần thức với Văn Thú, đọc trọn ký ức: nó đã lột xác tiến hóa, cắn nuốt chín đồng bọn, hóa mười vạn phần tìm chủ, mang hắn và Lý Mộ Uyển vào hư vô. Vương Lâm cảm động coi Văn Thú như thân nhân. Hắn chạm xác đá bị lực phản chấn hất ra, ngộ ra toàn bộ tu vi khôi phục là nhờ phân thân đang trưởng thành trong pháp tắc Tiên Cương. Liên hệ thuyết phong thủy long mạch, hắn quyết định không phá xác đá mà để phân thân tự chờ cơ duyên, tin rằng ngày phân thân trưởng thành sẽ gây đại biến thiên địa. Hắn mang Lý Mộ Uyển trong Tị Thiên Quan, cưỡi Văn Thú lao về cửa ra hư vô. Cùng lúc, Tiên Cương đại lục xảy ra đại biến hiếm thấy: hư ảnh Tiên Tổ mặc kim bào tái xuất sau vô số vạn năm trên Trung Châu Tiên Minh Châu, kim thiên hắc địa bao phủ ba mươi bảy châu, các Đại Thiên Tôn Tiên Tộc vái sâu; đồng thời ngân nhãn Cổ Tổ hiện trong dòng xoáy đen trên ba mươi sáu quận Cổ Quốc, con dân quỳ lạy, chín Đại Thiên Tôn cùng xuất hiện. Giữa Tiên Tộc và Cổ Tộc bất ngờ xuất hiện dòng xoáy khổng lồ thứ ba, cả đại lục khiếp sợ suy đoán trong đó tồn tại một người sánh ngang Cổ Tổ và Tiên Tổ."},{"chuong":1705,"tieuDe":"Tiên Cương Đại Lục, Ta Tới Rồi!","tomTat":"Dòng xoáy thứ ba xuất hiện giữa xoáy của Cổ Tổ và Tiên Tổ trên bầu trời Tiên Cương đại lục, khiến toàn đại lục chấn động, ngay cả Cửu Dương cũng ngưng trọng, rồi cả ba dòng xoáy đồng thời tiêu tán, để lại nỗi hoảng sợ mọc rễ trong lòng mọi người. Phân thân Vương Lâm nằm trong vùng đất sơ khai — một phần thạch đài nơi Tiên Tổ và Cổ Tổ ra đời — nhờ đó đắc mệnh cách ngang hai Tổ, vượt qua mọi cực hạn tu vi, tuy Vương Lâm chỉ mơ hồ suy đoán và tin vào nỗ lực của bản thân hơn. Trên Tiên Cương, hai đứa trẻ khác thường lộ diện: một đứa bé hơn mười tuổi chống nạnh vung gậy chấp nhất muốn làm vương gia đang dự khảo hạch tông môn, và một thiếu niên dáng tiên đồng hành nghề lừa gạt tự xưng tu sĩ chuyển thế — nghi tương ứng Tư Đồ Nam và Lưu Kim Bưu chuyển thế. Trong hư vô, Văn Thú hóa sương mù cuốn Vương Lâm bay suốt khoảng mười ba năm tìm cửa ra Tiên Cương, dọc đường hưng phấn vui sướng như đi theo cha mẹ. Vương Lâm dồn toàn bộ tu vi bảo vệ Lý Mộ Uyển nằm trong Tị Thiên Quan trên lưng, tự nhận mang theo nàng chẳng khác nào từ bỏ huyết mạch. Đặt mục tiêu tới Đông Lâm Tông tiến vào Đông Lâm Trì cầu phân thân bổn nguyên để đánh Không Kiếp, nhớ các cố nhân chuyển thế trên Tiên Cương. Văn Thú kiệt sức hóa sương mù không định hình lại được, Vương Lâm đau lòng thu nó thành dấu ấn trên cánh tay. Cuối cùng bạo phát toàn lực cõng Lý Mộ Uyển xông qua khe hở, thân thể như bị thiêu đốt nhưng mắt sáng ngời, chính thức đặt chân tới Tiên Cương đại lục."},{"chuong":1706,"tieuDe":"Có Điều Cổ Quái, Có Vấn Đề, Có Bảo Bối","tomTat":"Chương giới thiệu Thiên Ngưu Châu thuộc Đông Châu trên Tiên Cương đại lục, nơi núi non trùng điệp và truyền thuyết bảy mươi hai châu Tiên Tộc mỗi châu là trận pháp trấn áp một thiên ngoại hung sát. Hai đại tông phái Quy Nhất Tông và Đại Hồn Môn chiếm cứ châu này, thuộc cửu tông thập tam môn Đông Châu. Vân Dật Phong, đệ tử trọng yếu Quy Nhất Tông, mười năm trước một kiếm đả thương chín đệ tử ba trưởng lão Đại Hồn Môn rồi tuyên bố có một tu sĩ tu đạo hơn hai ngàn năm mà hắn không dám xuất kiếm trước mặt, cả hai đại tông đều im lặng như biết người này. Thương Long Tông là tông trung tầng do Đỗ Thanh sáng lập, chuyên giết người đoạt bảo, môn quy câu đầu là tiêu đề chương. Khang Nhân, đệ tử đời thứ ba Thương Long Tông, đang săn mồi ở biên giới châu thì chứng kiến bầu trời nứt ra khe, một thân ảnh sau lưng có quan tài rơi xuống đụng sụp hơn phân nửa lưng chừng núi. Lộ ra thanh niên tóc bạc nằm bất động trong đá vụn, thân thể cực mạnh. Khang Nhân nhớ môn quy, nổi lòng tham, xuất pháp bảo hộ thân cẩn thận tiến lại gần."},{"chuong":1707,"tieuDe":"Mang Hung Thần Về Phủ","tomTat":"Khang Nhân, đệ tử Thương Long Tông, phát hiện Vương Lâm nằm chết giả trên ngọn núi sụp, sinh khí tiêu tán hết. Hắn nhận định đối phương không phải Cổ Thần, Cổ Tộc hay tu sĩ Cổ Quốc, ném ngọc giản uy lực Tịnh Niết thử nhưng thân Vương Lâm hoàn toàn vô tổn. Khang Nhân nổi tà niệm khi thấy nữ tử ngủ say trong Tị Thiên Quan, tung lưới phong ấn bao trùm cả người lẫn quan tài, hóa hắc phong cuốn về sơn môn Thương Long Tông. Tại cốc khẩu, Hư Vân (thanh niên lưng gù) chặn hỏi nhưng bị gạt, lưu khôi lỗi thế chỗ gác rồi bổn tôn bám theo. Khang Nhân đóng cửa động phủ, dốc mười phần tài liệu kích hoạt trận pháp hút địa hỏa từ lòng đất luyện khôi lỗi. Hư Vân quỳ báo sư tôn (lão già tóc bạc, Không Niết sơ kỳ), xin đoạt bảo bối; sư tôn cảm nhận lượng địa hỏa bất thường liền dẫn đệ tử đi xem. Trong trận, địa hỏa không hại nổi Vương Lâm mà ngược lại chui vào cơ thể hắn. Đúng lúc ấy Vương Lâm đột nhiên mở mắt, ấn ký hình Văn Thú trên tay phải cũng mở bừng đôi mắt, lộ vẻ lạnh lùng tàn nhẫn đáng sợ."},{"chuong":1708,"tieuDe":"Địa Hỏa Biến","tomTat":"Vương Lâm lần đầu mở mắt trên Tiên Cương đại lục, xem xét Tị Thiên Quan rồi cảm nhận khí tức xung quanh. Hỏa bổn nguyên trong cơ thể hắn dung hợp với địa hỏa bản địa, xảy ra lột xác chưa từng có — trận chiến quyết định ai làm chủ hỏa diễm thiên địa. Hắn phát hiện Khang Nhân đang dùng trận pháp luyện mình thành khôi lỗi, khinh thường trận pháp này rồi dùng thần thức thăm dò hệ thống địa hỏa khổng lồ dưới lòng đất. Vương Lâm vỗ tay hút toàn bộ địa hỏa dãy núi đổ dồn vào động phủ, trận pháp nổ tung, chín khôi lỗi và hai khôi lỗi gỗ bị phá hủy, biển lửa bùng lên thành cột lửa thiêu hủy lầu các Thương Long Tông. Hắn phóng u quang bảo vệ Khang Nhân không bị chết. Sư tôn Hư Vân cảm nhận biến cố, chỉ ra nguyên nhân do Khang Nhân mang thi thể về luyện. Triệu trưởng lão — cường giả Không Linh hậu kỳ — hạ lệnh đệ tử sơ tán, tự mình hóa giọt nước ba trượng xông vào biển lửa điều tra, nhìn thấy Khang Nhân đang run rẩy kinh hãi trước cột lửa."},{"chuong":1709,"tieuDe":"Trận Chiến Đầu Tiên Ở Tiên Cương Đại Lục","tomTat":"Triệu trưởng lão Thương Long Tông (Không Linh hậu kỳ) xâm nhập động phủ Khang Nhân khi phát hiện cột lửa dị thường, nhưng bị Vương Lâm chỉ một tiếng quát kèm phất tay đánh bay hơn ngàn trượng, phun ba ngụm máu trọng thương — nước mưa lơ lửng không rơi, vạn vật bất động. Sư tôn Hư Vân nhận ra lời nói mang quy tức, đoán tu vi Không Huyền hoặc cao hơn. Vương Lâm dùng thần thức quét ký ức Khang Nhân, nắm được tông chủ Thương Long Tông tu vi Không Huyền sơ kỳ, lão tổ Đỗ Thanh tu vi Không Kiếp sơ kỳ, đều đang xuất ngoại. Hắn phát hiện Không Gian trữ vật không thể mở ra ở Tiên Cương đại lục, không lấy được Pháp Bảo lẫn Dĩ Ti khôi lỗi, đồng thời nhận thấy bổn nguyên nơi đây có biến hóa cần làm quen. Triệu trưởng lão sợ lão tổ nổi giận, hạ lệnh bốn trưởng lão cùng cả vạn đệ tử bỏ qua Thiên Thủy Trận, tổng lực thi triển Đạo Hồn Thuật — đạo pháp trấn phái nguồn gốc từ Đại Hồn Môn — tấn công hồn phách Vương Lâm. Vương Lâm dùng Tâm Động Lôi Âm đối kháng, rồi ra tay định lấy hồn phách địa hỏa mạch."},{"chuong":1710,"tieuDe":"Lão Tổ Trở Về!","tomTat":"Mấy vạn đệ tử Thương Long Tông đồng loạt thi triển Đạo Hồn Thuật liên kích quấy nhiễu hồn phách Vương Lâm, bị hắn dùng Tâm Động Lôi Âm phản chế, nhịp tim hóa lôi đình dẫn động tâm tạng mấy vạn tu sĩ. Vương Lâm bước ra khỏi động phủ, thi triển thuật rút hồn học từ động phủ giới, rút hồn phân mạch địa hỏa dưới dãy núi Thương Long Tông, triệu hoán hỏa long mấy vạn trượng phá sập toàn bộ ngọn núi thành tro bụi. Cưỡi hỏa long bay lên trời, tứ đại trưởng lão liều chết ngăn cản nhưng bất lực: nam tử trung niên bị thiêu cháy hai tay, ba trưởng lão còn lại vỡ thân thể chỉ còn Nguyên Thần. Vương Lâm lưu lời lạnh lùng nói tai họa do Thương Long Tông muốn luyện hắn thành khôi lỗi, rồi cưỡi hỏa long bay đi. Hắn phát hiện địa hỏa mạch Thiên Ngưu Châu kết cấu phức tạp giống trận pháp khổng lồ phong ấn vật gì đó chưa rõ. Một nén nhang sau, lão tổ Thương Long Tông trở về dưới hình dạng thiếu niên anh tuấn, phát tiếng gầm phẫn nộ dập tắt toàn bộ lửa, trầm mặc nhìn cảnh đổ nát với sát khí dữ tợn. Một nữ tử thiên kiều bá mị đi cùng lão tổ thấy cảnh tượng liền sợ hãi tránh xa."},{"chuong":1711,"tieuDe":"Vấn Đề Không Gian Trữ Vật","tomTat":"Tông chủ Thương Long Tông Đỗ Thanh (Không Kiếp sơ kỳ) trở về phát hiện tông phái bị hủy, nổi giận giết mấy ngàn đệ tử, soát hồn lấy hình dáng Vương Lâm, biến trưởng lão Tôn Mộng thành khôi lỗi trừng phạt, ra lệnh toàn tông truy tìm Vương Lâm trong ba tháng và thông cáo cả Thiên Ngưu Châu. Vương Lâm bay trong Tiên Cương đại lục, phát hiện thần thức bị áp chế chỉ còn một nửa và súc địa thành thốn mất tác dụng vì thiên địa nơi đây là thật. Từ trí nhớ Khang Nhân, hắn biết Thiên Ngưu Châu có Quy Nhất Tông và Đại Hồn Môn là hai tông phái tối cường. Vương Lâm than rằng tới chậm, sư tôn hẳn không đợi, xác định mục tiêu trước mắt là tới Đông Lâm Tông vào Đông Lâm Trì, dài hạn là tới Thất Đạo Tông tìm sư tôn. Sau nửa tháng di chuyển, hắn lập thạch thất bế quan trong vùng núi trùng điệp, thử mở Không Gian trữ vật nhưng khe chứa vật hỗn tạp vừa hiện ra liền sụp đổ tiêu tán. Hắn liệt kê các pháp bảo quan trọng bị kẹt: Huyết Kiếm, kim ấn sư tôn, Côn Cực Tiên, Dĩ Ti khôi lỗi và tấm buồm mặt quỷ."},{"chuong":1712,"tieuDe":"Nhớ Tới Tham Lang!","tomTat":"Sau vụ thiêu đốt Thương Long Tông, Đỗ Thanh đích thân tản thần thức truy tìm Vương Lâm nhưng không phát hiện do cấm chế quá bất phàm. Vương Lâm ẩn nấp một tháng, hấp thụ tiên khí Tiên Cương nuôi dưỡng toàn thân, nghiên cứu sự khác biệt bổn nguyên giữa động phủ giới và Tiên Cương đại lục. Hắn quyết định mở Không Gian trữ vật cũ dù có nguy cơ sụp đổ: khuếch tán tu vi ngưng đọng động phủ, dùng Định Thân Thuật dừng khe trữ vật, thần thức điên cuồng cuốn đồ ra. Lấy được Huyết Kiếm và kim ấn màu vàng nhưng người điên cùng nữ tử áo bạc bị cuốn vào khe biến mất, ba pháp bảo chưa vỡ cũng bị cuốn đi song đã đóng dấu ấn thần thức. Vương Lâm tạo Không Gian trữ vật mới trên cổ tay phải theo phương pháp Tiên Cương đại lục, thu Huyết Kiếm và kim ấn vào, luyện tập thuần thục. Hắn nghĩ tới Tham Lang, tin rằng đã ở Tiên Cương đại lục, đặt nghi vấn vì sao Tham Lang không cần chuyển thế như Thanh Thủy và Tư Đồ Nam. Tại hoàng đô Tiên Tộc trung châu, nam tử trung niên mặc long bào ngồi trên long ỷ trong đại điện vạn trượng, nhắc tới quốc sư tính toán Đạo Phi mất tích gặp tạo hóa và khí tức tại thần táng chỉ hư, rồi giơ tay túm về phía hư vô."},{"chuong":1713,"tieuDe":"Đại Bổ!","tomTat":"Nam tử mặc hoàng bào ngồi trên long ỷ trong đại điện hoàng cung, dùng thần thông mở vòng xoáy kéo người điên (Đạo Phi thân vương) và ngân y nữ tử ra trong trạng thái hôn mê. Hắn hai lần thi triển tiên lực vô biên cứu chữa Đạo Phi, đả thông kinh mạch bế tắc và xua tan uế khí tích tụ vô số năm. Người điên tỉnh dậy kêu “Ca!” rồi phun máu lại bất tỉnh, được lệnh đưa đi nghỉ ngơi. Nam tử hoàng bào trầm tư về việc Đạo Phi mất tích nhiều năm, bị thương nặng, huyết mạch ít đi. Trong khi đó, Vương Lâm bế quan trong động phủ trên ngọn núi ở Thiên Ngưu Châu, luyện hỏa bổn nguyên, phát hiện ngọn lửa bản thân bị địa hỏa bản địa bài xích mạnh mẽ, nếu không giải quyết sẽ thành điểm chí mạng khi giao chiến. Vương Lâm dùng Nguyên Thần hóa Hỏa Chu Tước xâm nhập lòng đất, gặp hỏa long — hồn phách địa hỏa dài mấy vạn trượng. Chủ động nhảy vào miệng hỏa long, từ bên trong hấp thụ và trấn áp hoàn toàn, khiến mặt đất rung chuyển, địa hỏa phun lên rồi co rút. Hỏa bổn nguyên của Vương Lâm lớn mạnh đáng kể, hắn nhìn xuống mặt đất lộ vẻ kỳ dị."},{"chuong":1714,"tieuDe":"Đỗ Thanh Hoảng Sợ!","tomTat":"Vương Lâm thanh trừ toàn bộ cấm chế trong động phủ, dùng lửa đốt sâu một trượng xóa dấu vết rồi rời đi với tốc độ cực nhanh. Ba ngày sau, Đỗ Thanh dẫn người tới nhưng đã chậm chân, phá sập ngọn núi và tính nhờ Đại Hồn Môn trợ giúp truy lùng. Vương Lâm phát hiện Thiên Ngưu Châu có hơn ngàn phân chi địa hỏa mạch, nhận ra Tiên Cương đại lục là bảo tàng cho mình vì thân phận ngoại lai từ động phủ giới bị hỏa nơi đây bài xích, chính sự bài xích cho phép hắn nghịch thiên cắn nuốt hồn phách địa hỏa. Hắn tìm thấy phân chi thứ hai với hỏa long ngàn trượng có lực ngang tu sĩ Không Linh, đánh một quyền nát đầu nó rồi triệu Chu Tước từ mắt trái hút sạch hồn phách. Chu Tước bành trướng tới mấy vạn trượng, hỏa bổn nguyên Vương Lâm tiến gần bổn nguyên chân thân. Hai ngày sau, Đỗ Thanh tới vùng núi thứ hai, thăm dò phát hiện chi địa hỏa mạch hoàn toàn khô héo tử vong, sắc mặt đại biến hoảng sợ vì trên Tiên Cương chưa từng có ai hấp thu được địa hỏa mạch."},{"chuong":1715,"tieuDe":"Quần Long Nhất Tước Thôn Địa Mạch!","tomTat":"Đỗ Thanh do dự nhưng cắn răng tiếp tục truy kích Vương Lâm, triệu hạc giấy đỏ (chỉ dẫn Đại Hồn Môn) dẫn đường. Vương Lâm cưỡi Chu Tước huyền hóa bay khắp Thiên Ngưu Châu suốt hơn hai mươi ngày, liên tục cắn nuốt hồn phách địa hỏa mạch, từ hai phân chi nâng lên tổng mười sáu long hồn, hỏa bổn nguyên vượt quá hai lần so với lúc ở động phủ giới. Đỗ Thanh tự bộc lộ tu vi thật chỉ bảy lần Huyền Kiếp chứ không phải Không Kiếp sơ kỳ như đối ngoại tuyên bố, song tự tin thân thể khôi lỗi gỗ cường hãn sánh tu sĩ Cổ Quốc. Tại phía bắc Thiên Ngưu Châu, Vương Lâm gặp một mạch con (tử mạch) cường đại tương đương tu sĩ Không Huyền trung kỳ, triệu mười sáu hỏa long bao quanh Chu Tước lao vào chiến đấu, tạo cảnh tượng quần long nhất tước thôn địa mạch. Đỗ Thanh đuổi tới đúng lúc, tiếng gầm long hồn dẫn động hỏa bổn nguyên trong thân hắn bùng ra, thân thiếu niên nứt hiện nguyên hình khôi lỗi gỗ. Hắn nhìn thấy Vương Lâm trên đỉnh đầu Chu Tước giữa mười sáu hỏa long, cảm giác như đối mặt ngọn núi cao."},{"chuong":1716,"tieuDe":"Khiến Đỗ Thanh Kinh Hãi!","tomTat":"Đỗ Thanh lao vào biển lửa định tấn công Vương Lâm khi hắn đang cắn nuốt địa hỏa mạch, nhưng Vương Lâm đã dự liệu trước, điều khiển Chu Tước cùng mười sáu hỏa long quấn chặt long hồn. Hỏa bổn nguyên của Vương Lâm tăng mạnh gấp mấy lần, một đạo bổn nguyên đã tương đương bảy đạo trước đây. Hai bên va chạm chưởng ấn và cánh tay gỗ khổng lồ, cả hai đều tan nát, nhưng Vương Lâm khéo léo chuyển toàn bộ lực phản kích của Đỗ Thanh xuống hỏa long, khiến nó bị thương nặng và đẩy nhanh quá trình cắn nuốt. Vương Lâm nhận định Đỗ Thanh vẫn ở Huyền Kiếp, chưa đạt Không Kiếp, uy lực không sánh bằng Chiến lão quỷ hay Thất Thải đạo nhân. Đỗ Thanh chất vấn về việc phá hủy Thương Long Tông, Vương Lâm đáp rằng đệ tử Thương Long Tông dám đem hắn luyện chế thành khôi lỗi, hắn chỉ hủy sơn môn mà không giết người đã là lưu tay. Vương Lâm liên tiếp thi triển Dịch Linh Ấn của Thế Giới Tông, Thất Thải Thuật của Đông Lâm Tông, và Phần Giới Cổ Tán — đạo thuật bất truyền của Tùng Vân Đạo, một trong ba đạo tông tối cường trên Tiên Cương. Ba thần thông chánh tông từ ba tông phái khác nhau khiến Đỗ Thanh da đầu tê dại, sắc mặt tái nhợt, kinh hãi hỏi Vương Lâm rốt cục là ai."},{"chuong":1717,"tieuDe":"Vương Lâm So Bổn Nguyên","tomTat":"Đỗ Thanh liên tục rung động khi nhận ra Vương Lâm biết pháp thuật của Thế Giới Tông, Đông Lâm Tông và cả Phần Giới Cổ Tán của Tùng Vân Đạo, suy đoán lai lịch đối phương hoặc giảo hoạt hoặc bối cảnh cực sâu. Vương Lâm muốn dọa Đỗ Thanh tự lui nhưng thất bại, bèn thi triển Hô Phong Hoán Vũ, Tát Đậu Thành Binh, Sơn Băng Địa Liệt rồi xuất thức mở đầu Âm Nguyệt Hữu Tình của Âm Nguyệt Tông — đại tông thứ tư trong cửu tông thập tam môn — khiến Đỗ Thanh sụp đổ tinh thần. Đỗ Thanh vì mất thể diện không thể lui, liều mạng triển khai ba đạo bổn nguyên: tử hỏa từ thân khôi lỗi gỗ, thổ bổn nguyên biến bốn phía thành hoang mạc, và trọng bổn nguyên cực hiếm — bổn nguyên nhờ thân khôi lỗi chứa một tia mà mò ra, cũng là lý do Đại Hồn Môn che chở hắn. Trọng bổn nguyên khiến hỏa có trọng lượng uy lực tăng vô số lần, thổ bổn nguyên như nắm cả đại lục. Ba đạo bổn nguyên đè sụp toàn bộ bốn thần thông của Vương Lâm, hỏa long hồn kêu thê lương sụp đổ thành hỏa cầu bao phủ hắn. Khi Đỗ Thanh định truy kích đòn trí mạng, từ trong hỏa cầu Vương Lâm hỏi ngược: ngươi cho rằng ta chỉ có một đạo bổn nguyên, ba đạo của ngươi đã là nhiều sao — khiến Đỗ Thanh chấn động tâm thần."},{"chuong":1718,"tieuDe":"Quá Gian Xảo!","tomTat":"Vương Lâm từ trong quả cầu hỏa long hồn lần lượt triệu hoán bảy đạo bổn nguyên trước mặt Đỗ Thanh: hỏa (thực), lôi (thực, dẫn động lôi biến hiện lôi đế chiến xa), sinh tử (hư), nhân quả (hư), chân giả (hư), sát lục (thực, từ mi tâm), cấm chế (thực, tơ máu từ đồng tử). Bảy đạo bổn nguyên — bốn thực ba hư — chưa từng nghe nói ngay cả ở Đại Hồn Môn. Đỗ Thanh liên tục lùi bước, kinh hãi trước sát lục bổn nguyên hiếm hơn cả trọng bổn nguyên, da đầu tê dại nảy ý bỏ chạy. Vương Lâm phóng kim ấn Đại Thiên Tôn — kim quang vạn trượng mang khí tức Đại Thiên Tôn — khiến Đỗ Thanh tự thương tâm thần phun máu. Đỗ Thanh nhận ra đây là pháp bảo do Đại Thiên Tôn dùng thiên địa thuật thực chất hóa thần thông ngưng tụ, đổi chủ không do chủ nhân trao thì tan vỡ, thường được Cửu Dương Đại Thiên Tôn trao cho môn nhân thân cận nhất để tuyên bố bất khả xâm phạm. Đỗ Thanh gào mắng Vương Lâm gian xảo, hoàn toàn bỏ ý truy sát. Bản thân Vương Lâm cũng ngẩn ra vì không ngờ kim ấn có sức chấn nhiếp lớn đến thế."},{"chuong":1719,"tieuDe":"Cảm Ứng Của Huyền La","tomTat":"Vương Lâm thu kim ấn mang khí tức Đại Thiên Tôn vào miệng, Đỗ Thanh bị trấn áp hoàn toàn bỏ ý truy sát. Đỗ Thanh nhận ra cơ duyên, quay lại nói dối là hiểu lầm, dùng thệ phù mượn pháp tắc Tiên Cương lập thề xin hộ pháp cho Vương Lâm. Vương Lâm nhìn thấu tâm tư nhưng đồng ý vì cần người bên cạnh và chiếm thế chủ động. Ba ngày sau, Vương Lâm hấp thụ hỏa bổn nguyên từ quả cầu lửa do tử mạch biến thành, mười sáu hỏa long dung hợp. Ngày thứ năm quả cầu lửa co rút từ mười trượng xuống một trượng, Chu Tước hiện bên trong, Đỗ Thanh nhận ra Vương Lâm đang ngưng tụ chân thân bổn nguyên — thứ cả đời hắn chỉ thấy trên lão tổ Đại Hồn Môn. Qua suy nghĩ của Đỗ Thanh lộ ra hệ thống phân cấp bổn nguyên: mới xuất hiện, ngưng tụ pháp khí, đại thành, chân thân bổn nguyên. Tại Thiên Không Quận thuộc hoàng tộc Đạo Cổ nhất mạch, Huyền La đang bế quan trên tế đàn, cảm ứng được kim ấn xuất hiện ở Thiên Ngưu Châu, mở mắt nói \"Hắn tới rồi!\", tin rằng đệ tử mà hắn chọn nhất định sẽ đến được Tiên Cương đại lục."},{"chuong":1720,"tieuDe":"Ngưng Tụ Bổn Nguyên Chân Thân!","tomTat":"Huyền La trầm ngâm quyết định không tới Tiên Tộc vì thân phận nhạy cảm, cho rằng có kim ấn thì Vương Lâm không ngại gì, bế quan thổ nạp tại Đạo Cổ nhất mạch chờ đồ nhi trở về. Trong Thiên Ngưu Châu, Vương Lâm bắt đầu ngưng tụ hỏa bổn nguyên chân thân thông qua hỏa cầu chứa Chu Tước, liên tục bắt quyết đánh ấn ký khiến Chu Tước hiện hình rõ. Hỏa cầu nổ tung, Chu Tước lông bốc cháy hóa hình người bắt đầu ngưng tụ, nhưng hỏa bổn nguyên không đủ, liều mạng toàn lực chỉ ngưng tụ được hai chân. Vương Lâm lao xuống đất triển khai thần thức phạm vi khổng lồ gần bằng động phủ giới, triệu hồi 172 long hồn phân mạch địa hỏa mạch lao vào hỏa cầu, Chu Tước hấp thu ngưng tụ thêm hai cánh tay, tứ chi hoàn thành nhưng còn thiếu thân và đầu. Vương Lâm tiếp tục triệu hồi long hồn hai mạch con, bản thân lao đón long hồn hải long dung nham, giao Đỗ Thanh kiềm chế long hồn còn lại trong nửa canh giờ. Đỗ Thanh lần đầu chứng kiến quá trình ngưng tụ chân thân, coi là cơ duyên lớn, cắn răng hóa thân hình khôi lỗi gỗ lao về phía long hồn."},{"chuong":1721,"tieuDe":"Nuối Tiếc Chân Thân","tomTat":"Đỗ Thanh thi triển trọng bổn nguyên trấn áp long hồn mạch con, Vương Lâm rút Huyết Kiếm chém đứt hỏa long hồn dung nham rồi dùng kim ấn Đại Thiên Tôn truy bắt giam giữ hỏa long hồn mạch con thứ hai. Ba long hồn lần lượt bị đưa vào hỏa cầu, bổn nguyên chân thân ngưng tụ gần hoàn chỉnh — thân hình và tứ chi đã thành hình, chỉ còn đầu vẫn thuộc Chu Tước chưa chuyển hóa. Vương Lâm cảm thán 188 phân chi cộng ba mạch con vẫn chưa đủ, tài nguyên động phủ giới căn bản không thể hoàn thành chân thân. Sau khi chân thân thu vào mắt trái, mắt trái biến đổi hiện hai đồng tử, phía sau xuất hiện hư ảnh ảnh tùy tâm động — Đỗ Thanh nhận ra giống hiện tượng lão tổ Đại Hồn Môn. Vương Lâm quyết định tới Thương Long Tông ở lại, Đỗ Thanh hứa huy động tài nguyên tông phái tìm địa hỏa mạch và long hồn. Trên đường bay, Đỗ Thanh ngầm tăng tốc thăm dò tu vi Vương Lâm, phán đoán hắn như Không Linh đỉnh phong nhưng thực lực khó lường. Vương Lâm triệu Văn Vương ra cưỡi đi, tốc độ kinh người bỏ xa Đỗ Thanh."},{"chuong":1722,"tieuDe":"Thanh Ngưu Chân Nhân","tomTat":"Vương Lâm cưỡi Văn Vương bay liên tục nửa tháng tới Thương Long Tông, Đỗ Thanh chật vật đuổi theo. Tới nơi, Đỗ Thanh giới thiệu Vương Lâm là chí giao đạo hữu có đại ân với Thương Long Tông, dẫn vào động phủ hậu sơn xa hoa nghênh đón. Vương Lâm hỏi về vị trí địa hỏa chủ mạch Thiên Ngưu Châu, Đỗ Thanh tiết lộ truyền thuyết: thời sơ khai Tiên Tổ giết thiên ngoại ngưu tinh, thân hóa thành Thiên Ngưu Châu, Nguyên Thần bị trấn áp dưới hỏa mạch, địa hỏa chủ mạch nằm ở Đại Hồn Môn. Lão tổ Đại Hồn Môn là Thanh Ngưu chân nhân, tu vi cao thâm, có bổn nguyên chân thân. Đỗ Thanh cho biết Phàn San Mộng là một trong song kiêu Đại Hồn Môn, và giới thiệu Vân Dật Phong (Quy Nhất Tông) là đệ nhất cao thủ Thiên Ngưu Châu. Khi kể lại lời Vân Dật Phong từng ca ngợi người tu đạo hơn hai ngàn năm mà không dám xuất kiếm trước mặt, Đỗ Thanh đột nhiên sinh nghi ngờ lớn rằng người đó chính là Vương Lâm. Vương Lâm mắt lóe sáng rồi lập tức nói lảng sang chuyện lôi mạch."},{"chuong":1723,"tieuDe":"Không Biết Lượng Sức?","tomTat":"Vương Lâm hỏi Đỗ Thanh về lôi mạch và Đông Lâm Tông, biết Đông Lâm Tông thuộc cửu tông thập tam môn ở Đại Thánh Châu hướng bắc Đông Châu, cực kỳ thần bí. Đỗ Thanh hạ lệnh Thương Long Tông phát động toàn lực tìm địa hỏa mạch, sai ba đại trưởng lão cầm đầu đệ tử đi ba hướng. Vương Lâm cân nhắc nhờ Đại Hồn Môn hoặc Quy Nhất Tông nhưng từ bỏ vì tính cách muốn tự lực. Hắn thử thi triển súc địa thành thốn trên Tiên Cương đại lục nhưng bị áp lực pháp tắc thiên địa ngăn cản, chỉ thuấn di khoảng cách ngắn. Suốt bảy tháng bế quan tản thần thức, mục đích thật là thúc dục tâm thần liên kết với phân thân trong xác đá vùng hư vô — phân thân sinh trong pháp tắc Tiên Cương chính là chìa khóa dung hợp thiên địa. Ép Nguyên Thần khô héo tới cùng cực, cuối tháng thứ bảy phân thân mở mắt bừng tỉnh, Đỗ Thanh từ khinh thường chuyển sang kinh hãi thốt lên chuyện này không có khả năng."},{"chuong":1724,"tieuDe":"Tuyết Trên Thiên Sơn","tomTat":"Thần thức Vương Lâm lượn quanh hậu sơn suốt bảy tháng bỗng tiêu tán hoàn toàn, Đỗ Thanh hoảng sợ tìm kiếm khắp nơi không thấy dấu vết. Vương Lâm toàn thân áo trắng bất ngờ xuất hiện phía sau Đỗ Thanh mang theo hàn khí thiên địa, rồi bay vào động phủ. Đỗ Thanh phát hiện tuyết xanh Thiên Sơn dính dưới chân Vương Lâm — chứng tỏ hắn đã di chuyển tức thời tới Thiên Sơn cực tây Thiên Ngưu Châu rồi quay về trong chưa hết một nén nhang, toàn bộ sự khinh thường bảy tháng qua tan thành mây khói, sinh ra nỗi sợ hãi sâu sắc. Trong động phủ, Vương Lâm xác nhận phân thân trong hư vô đã thức tỉnh truyền lại cảm ngộ, phá vỡ phép tắc Tiên Cương, thần thức dung nhập thiên địa, khôi phục thuật Súc Địa Thành Thốn. Đỗ Thanh mang hỏa hồn và ngọc giản bản đồ tử mạch Thiên Ngưu Châu tới bái kiến nhưng không đi báo tin vì còn mưu đồ riêng. Vương Lâm dùng bảy ngày phá hủy các địa hỏa tử mạch khắp Thiên Ngưu Châu để ngưng tụ hỏa bổn nguyên chân thân, nhận ra phần đầu cần hỏa ý chí. Nửa tháng sau ghé di chỉ Thất Đạo Tông, cảm nhận Huyền La chờ đợi và nhớ về Tư Đồ, Thanh Thủy, Lý Thiến Mai đã chuyển thế đầu thai. Cuối cùng tới đỉnh Thiên Sơn dưới tuyết xanh, nhắm mục tiêu Đại Hồn Môn với ngọn núi đỏ cao chọc trời."}];
